   1→import { createContext, useContext, useReducer } from 'react';
   2→import { createProject } from '@/domain/models';
   3→import { clearProjectPhaseReferences } from '@/domain/phaseAssignments';
   4→import { createDuplicatedFloor, getDefaultFloorName, getFloorElevation, getFloorLevelIndex, shiftFloorAbsoluteElements, shiftFloorElevationData, sortFloors } from '@/domain/floorModels';
   5→import { sortPhases } from '@/domain/phaseModels';
   6→import { getRoofAttachmentElevation, syncProjectRoofSystem } from '@/domain/roofModels';
   7→import { syncProjectTrussSystems } from '@/domain/trussModels';
   8→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
   9→import { syncStairLandingAttachment } from '@/geometry/landingGeometry';
  10→import { clampWallOpeningOffset, wallLength } from '@/geometry/wallGeometry';
  11→
  12→const ProjectContext = createContext(null);
  13→const HISTORY_LIMIT = 100;
  14→
  15→function snapshotProject(project) {
  16→  return JSON.stringify(project);
  17→}
  18→
  19→function syncProjectStructures(project) {
  20→  return syncProjectRoofSystem(syncProjectTrussSystems(project));
  21→}
  22→
  23→function applyProjectUpdate(state, nextProject, recordHistory = true) {
  24→  const syncedProject = syncProjectStructures(nextProject);
  25→  const nextSnapshot = snapshotProject(syncedProject);
  26→  const history = recordHistory
  27→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
  28→    : state.history;
  29→
  30→  return {
  31→    ...state,
  32→    history,
  33→    future: recordHistory ? [] : state.future,
  34→    project: syncedProject,
  35→    isDirty: nextSnapshot !== state.savedSnapshot,
  36→  };
  37→}
  38→
  39→function updateFloor(state, floorId, updater, recordHistory = true, options = {}) {
  40→  const nextFloors = state.project.floors.map((floor) => (
  41→    floor.id === floorId ? updater(floor) : floor
  42→  ));
  43→
  44→  return applyProjectUpdate(state, {
  45→    ...state.project,
  46→    updatedAt: new Date().toISOString(),
  47→    floors: options.sort ? sortFloors(nextFloors) : nextFloors,
  48→  }, recordHistory);
  49→}
  50→
  51→function replaceFloors(state, floors, recordHistory = true) {
  52→  return applyProjectUpdate(state, {
  53→    ...state.project,
  54→    updatedAt: new Date().toISOString(),
  55→    floors: sortFloors(floors),
  56→  }, recordHistory);
  57→}
  58→
  59→function replaceDeletedFloorReferences(project, deletedFloorId, fallbackFloorId) {
  60→  return {
  61→    ...project,
  62→    floors: project.floors.map((floor) => ({
  63→      ...floor,
  64→      stairs: (floor.stairs || []).map((stair) => ({
  65→        ...stair,
  66→        floorRelation: {
  67→          fromFloorId: stair.floorRelation?.fromFloorId === deletedFloorId
  68→            ? fallbackFloorId
  69→            : (stair.floorRelation?.fromFloorId ?? floor.id),
  70→          toFloorId: stair.floorRelation?.toFloorId === deletedFloorId
  71→            ? fallbackFloorId
  72→            : (stair.floorRelation?.toFloorId ?? floor.id),
  73→        },
  74→      })),
  75→    })),
  76→    sheets: (project.sheets || []).map((sheet) => ({
  77→      ...sheet,
  78→      viewports: (sheet.viewports || []).map((viewport) => ({
  79→        ...viewport,
  80→        sourceFloorId: viewport.sourceFloorId === deletedFloorId
  81→          ? fallbackFloorId
  82→          : viewport.sourceFloorId,
  83→        sourceRefId: viewport.sourceFloorId === deletedFloorId
  84→          ? null
  85→          : viewport.sourceRefId,
  86→      })),
  87→    })),
  88→  };
  89→}
  90→
  91→function clearStairRoofAccessReferences(project, roofOpeningId = null) {
  92→  return {
  93→    ...project,
  94→    floors: (project.floors || []).map((floor) => ({
  95→      ...floor,
  96→      stairs: (floor.stairs || []).map((stair) => {
  97→        const currentRoofOpeningId = stair.roofAccess?.roofOpeningId || null;
  98→        if (!currentRoofOpeningId) return stair;
  99→        if (roofOpeningId && currentRoofOpeningId !== roofOpeningId) return stair;
 100→        return {
 101→          ...stair,
 102→          roofAccess: null,
 103→        };
 104→      }),
 105→    })),
 106→  };
 107→}
 108→
 109→function updateRoofSystem(state, updater, recordHistory = true) {
 110→  const nextRoofSystem = updater(state.project.roofSystem);
 111→  return applyProjectUpdate(state, {
 112→    ...state.project,
 113→    updatedAt: new Date().toISOString(),
 114→    roofSystem: nextRoofSystem,
 115→  }, recordHistory);
 116→}
 117→
 118→function updateTrussSystems(state, updater, recordHistory = true) {
 119→  const nextTrussSystems = updater(state.project.trussSystems || []);
 120→  return applyProjectUpdate(state, {
 121→    ...state.project,
 122→    updatedAt: new Date().toISOString(),
 123→    trussSystems: nextTrussSystems,
 124→  }, recordHistory);
 125→}
 126→
 127→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 128→  const nextWall = { ...existingWall, ...wallUpdate };
 129→
 130→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 131→    nextWall.startAttachment = null;
 132→  }
 133→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 134→    nextWall.endAttachment = null;
 135→  }
 136→
 137→  return syncWallAttachmentPoints(nextWall, columns);
 138→}
 139→
 140→function clampWallMountedOpenings(openings, wallId, nextWallLength) {
 141→  return openings.map((opening) => {
 142→    if (opening.wallId !== wallId) return opening;
 143→
 144→    const nextOffset = clampWallOpeningOffset(nextWallLength, opening.width, opening.offset);
 145→    return nextOffset === opening.offset ? opening : { ...opening, offset: nextOffset };
 146→  });
 147→}
 148→
 149→function projectReducer(state, action) {
 150→  switch (action.type) {
 151→    case 'PROJECT_NEW': {
 152→      const newProject = syncProjectStructures({
 153→        ...action.project,
 154→        floors: sortFloors(action.project.floors || []),
 155→      });
 156→      return {
 157→        project: newProject,
 158→        isDirty: false,
 159→        lastSavedAt: null,
 160→        savedSnapshot: snapshotProject(newProject),
 161→        history: [],
 162→        future: [],
 163→      };
 164→    }
 165→
 166→    case 'PROJECT_LOAD': {
 167→      const loadedProject = syncProjectStructures({
 168→        ...action.project,
 169→        floors: sortFloors(action.project.floors || []),
 170→      });
 171→      return {
 172→        project: loadedProject,
 173→        isDirty: false,
 174→        lastSavedAt: action.savedAt || null,
 175→        savedSnapshot: snapshotProject(loadedProject),
 176→        history: [],
 177→        future: [],
 178→      };
 179→    }
 180→
 181→    case 'PROJECT_SET_NAME':
 182→      return applyProjectUpdate(state, {
 183→        ...state.project,
 184→        name: action.name,
 185→        updatedAt: new Date().toISOString(),
 186→      });
 187→
 188→    case 'PROJECT_UPDATE':
 189→      return applyProjectUpdate(state, {
 190→        ...state.project,
 191→        ...action.updates,
 192→        updatedAt: new Date().toISOString(),
 193→      });
