199→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId });
200→    if (phaseViewMode === 'all') {
201→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'single' });
202→    }
203→    editorDispatch({ type: 'SELECT_OBJECT', id: phaseId, objectType: 'phase' });
204→  };
