  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { filterProjectByPhase } from '@/domain/phaseFilter';
  4→import { buildPreviewScene } from '@/three/scene/buildPreviewScene';
  5→import { buildPreviewObjectRoot } from './buildPreviewObjects';
  6→import { createPreviewViewport } from './createPreviewViewport';
  7→import { getOrderedFloors } from '@/domain/floorModels';
  8→import { getPreviewInspection } from './previewInspection';
  9→import { resolveWalkFloorContext } from './resolveWalkFloorContext';
 10→import CompassOverlay from '@/ui/CompassOverlay';
 11→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 12→import styles from './ThreePreviewPanel.module.css';
 13→
 14→export default function ThreePreviewPanel({ project, activeFloorId, isMaximized = false, onToggleMaximize, className = '' }) {
 15→  const viewportRef = useRef(null);
 16→  const containerRef = useRef(null);
 17→  const resizeObserverRef = useRef(null);
 18→  const compassNeedleRef = useRef(null);
 19→  const [previewScope, setPreviewScope] = useState('all');
 20→  const [navigationMode, setNavigationMode] = useState('inspect');
 21→  const [walkUiState, setWalkUiState] = useState({
 22→    navigationMode: 'inspect',
 23→    isLocked: false,
 24→    canLock: false,
 25→  });
 26→  const { selectedId, selectedType, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
 27→
 28→  const filteredProject = useMemo(
 29→    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 30→    [project, activePhaseId, phaseViewMode]
 31→  );
 32→
 33→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
 34→
 35→  const visibleFloorIds = useMemo(() => {
 36→    if (previewScope === 'all') return undefined;
 37→    if (orderedFloors.some((f) => f.id === previewScope)) return [previewScope];
 38→    return undefined;
 39→  }, [previewScope, orderedFloors]);
 40→
 41→  const sceneDescriptor = useMemo(() => buildPreviewScene(filteredProject, {
 42→    activeFloorId,
 43→    visibleFloorIds,
 44→  }), [filteredProject, activeFloorId, visibleFloorIds]);
 45→
 46→  const activeFloor = (project?.floors || []).find((floor) => floor.id === activeFloorId) || null;
 47→  const visibleCount = sceneDescriptor.floors
 48→    .filter((floor) => floor.visible)
 49→    .reduce((count, floor) => count + floor.objects.length, 0);
 50→  const visibleFloorCount = sceneDescriptor.floors
 51→    .filter((floor) => floor.visible && floor.floorId !== sceneDescriptor.roofLayerId)
 52→    .length;
 53→  const inspection = useMemo(
 54→    () => getPreviewInspection(project, selectedType, selectedId),
 55→    [project, selectedId, selectedType]
 56→  );
 57→  const walkFloorContext = useMemo(
 58→    () => resolveWalkFloorContext(sceneDescriptor, activeFloorId),
 59→    [sceneDescriptor, activeFloorId]
 60→  );
 61→  const visibleInspection = inspection && sceneDescriptor.visibleFloorIds.includes(inspection.floorId)
 62→    ? inspection
 63→    : null;
 64→  const handlePreviewScopeChange = useCallback((nextScope) => {
 65→    setPreviewScope(nextScope);
 66→
 67→    if (nextScope === 'all') return;
 68→    if (!orderedFloors.some((floor) => floor.id === nextScope)) return;
 69→    if (nextScope !== activeFloorId) {
 70→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: nextScope });
 71→    }
 72→  }, [activeFloorId, editorDispatch, orderedFloors]);
 73→  const handlePreviewPick = useCallback((target) => {
 74→    if (!target?.sourceId || !target?.kind) {
 75→      editorDispatch({ type: 'DESELECT' });
 76→      return;
 77→    }
 78→
 79→    if (target.floorId && target.floorId !== activeFloorId) {
 80→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: target.floorId });
 81→    }
 82→
 83→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 84→  }, [activeFloorId, editorDispatch]);
 85→
 86→  useEffect(() => {
 87→    if (!containerRef.current) return undefined;
 88→
 89→    const viewport = createPreviewViewport(containerRef.current);
 90→    viewportRef.current = viewport;
 91→
 92→    if ('ResizeObserver' in window) {
 93→      const observer = new ResizeObserver(() => {
 94→        viewport.resize();
 95→      });
 96→      observer.observe(containerRef.current);
 97→      resizeObserverRef.current = observer;
 98→    }
 99→
100→    viewport.resize();
101→
102→    return () => {
103→      resizeObserverRef.current?.disconnect?.();
104→      resizeObserverRef.current = null;
105→      viewport.dispose();
106→      viewportRef.current = null;
107→    };
108→  }, []);
109→
110→  useEffect(() => {
111→    viewportRef.current?.setPickHandler(handlePreviewPick);
112→  }, [handlePreviewPick]);
113→
114→  useEffect(() => {
115→    viewportRef.current?.setPickContext({ activeFloorId });
116→  }, [activeFloorId]);
117→
118→  useEffect(() => {
119→    viewportRef.current?.setWalkUiHandler(setWalkUiState);
120→    viewportRef.current?.setWalkExitHandler(() => {
121→      setNavigationMode('inspect');
122→    });
123→  }, []);
124→
125→  useEffect(() => {
126→    viewportRef.current?.setCompassHeadingHandler((headingDeg) => {
127→      if (!compassNeedleRef.current) return;
128→      compassNeedleRef.current.style.setProperty('--compass-heading', `${headingDeg}deg`);
129→    });
130→
131→    return () => {
132→      viewportRef.current?.setCompassHeadingHandler(null);
133→    };
134→  }, []);
135→
136→  useEffect(() => {
137→    const viewport = viewportRef.current;
138→    if (!viewport) return;
139→
140→    const root = buildPreviewObjectRoot(sceneDescriptor, viewport.materialPalette, {
141→      selectedId,
142→      selectedType,
143→    });
144→    viewport.setWorld(root, sceneDescriptor.bounds, sceneDescriptor.groundLevel);
145→  }, [sceneDescriptor, selectedId, selectedType]);
146→
147→  useEffect(() => {
148→    viewportRef.current?.setNavigationMode(navigationMode);
149→  }, [navigationMode]);
150→
151→  useEffect(() => {
152→    viewportRef.current?.setActiveFloorContext(walkFloorContext);
153→  }, [walkFloorContext]);
154→
155→  const resetLabel = navigationMode === 'walk' ? 'Reset Walk' : 'Reset View';
156→  const primaryFooter = navigationMode === 'walk'
157→    ? (walkUiState.isLocked
158→      ? 'Look: mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc'
159→      : 'Walk: click preview to capture mouse · Fly: W/A/S/D · Up/Down: R/F · Faster: Shift · Exit: Esc')
160→    : 'Orbit: drag · Pan: right drag · Zoom: wheel · Inspect: click object';
161→  const secondaryFooter = navigationMode === 'walk'
162→    ? 'Ghost walk is noclip flight now, still read-only and collision-free.'
163→    : 'Perspective preview, future-ready for presets and floor visibility.';
164→
165→  return (
166→    <section className={`${styles.panel} ${className}`}>
167→      <div className={styles.header}>
168→        <div className={styles.titleGroup}>
169→          <span className={styles.eyebrow}>3D Preview</span>
170→          <span className={styles.title}>
171→            {activeFloor
172→              ? `${visibleFloorCount === 1 ? '1 floor' : `${visibleFloorCount} floors`} · ${visibleCount} objects`
173→              : 'No active floor'}
174→          </span>
175→        </div>
176→        <div className={styles.actions}>
177→          <div className={styles.modeToggle} role="group" aria-label="Preview navigation mode">
178→            <button
179→              type="button"
180→              className={navigationMode === 'inspect' ? styles.modeButtonActive : styles.modeButton}
181→              onClick={() => setNavigationMode('inspect')}
182→              aria-pressed={navigationMode === 'inspect'}
183→            >
184→              Inspect
185→            </button>
186→            <button
187→              type="button"
188→              className={navigationMode === 'walk' ? styles.modeButtonActive : styles.modeButton}
189→              onClick={() => setNavigationMode('walk')}
190→              aria-pressed={navigationMode === 'walk'}
191→            >
192→              Walk
193→            </button>
194→          </div>
195→          <select
196→            className={styles.floorSelect}
197→            value={previewScope}
198→            onChange={(e) => handlePreviewScopeChange(e.target.value)}
199→          >
200→            <option value="all">All Floors</option>
201→            {orderedFloors.map((floor) => (
202→              <option key={floor.id} value={floor.id}>{floor.name}</option>
203→            ))}
204→          </select>
205→          <button
206→            type="button"
207→            className={styles.button}
208→            onClick={() => viewportRef.current?.resetView()}
209→          >
210→            {resetLabel}
211→          </button>
212→          {onToggleMaximize && (
213→            <button
214→              type="button"
215→              className={`${styles.button} ${styles.iconButton}`}
216→              onClick={onToggleMaximize}
217→              title={isMaximized ? 'Restore split view' : 'Maximize preview'}
218→              aria-label={isMaximized ? 'Restore split view' : 'Maximize preview'}
219→            >
220→              {isMaximized ? <CollapseIcon /> : <ExpandIcon />}
221→            </button>
222→          )}
223→        </div>
224→      </div>
225→
226→      <div className={styles.viewportWrap}>
227→        <div ref={containerRef} className={styles.viewport} />
228→        <CompassOverlay className={styles.compassDock} needleRef={compassNeedleRef} />
229→        {navigationMode === 'walk' && (
230→          <div className={styles.walkOverlay}>
231→            <span className={styles.walkOverlayTitle}>
232→              {walkUiState.isLocked ? 'Walk Mode Active' : 'Walk Mode Ready'}
233→            </span>
234→            <span className={styles.walkOverlayBody}>
235→              {walkUiState.isLocked
236→                ? 'Noclip flight is live. W/S follow the camera view, A/D strafe, R/F move up and down, Shift goes faster, and Esc exits.'
237→                : 'Click inside the preview to capture the mouse, then use W/A/S/D for noclip flight and R/F for vertical movement.'}
238→            </span>
239→          </div>
240→        )}
241→        {visibleInspection && (
242→          <div className={styles.inspectCard}>
243→            <span className={styles.inspectEyebrow}>Selected Object</span>
244→            <span className={styles.inspectTitle}>{visibleInspection.title}</span>
245→            <span className={styles.inspectMeta}>{visibleInspection.subtitle}</span>
246→            <div className={styles.inspectGrid}>
247→              {visibleInspection.rows.map((row) => (
248→                <div key={`${visibleInspection.id}-${row.label}`} className={styles.inspectRow}>
249→                  <span className={styles.inspectLabel}>{row.label}</span>
250→                  <span className={styles.inspectValue}>{row.value}</span>
251→                </div>
252→              ))}
253→            </div>
254→          </div>
255→        )}
256→        {!sceneDescriptor.hasVisibleObjects && (
257→          <div className={styles.emptyState}>
258→            <span className={styles.emptyTitle}>Scene Empty</span>
259→            <span className={styles.emptyBody}>
260→              Add walls, slab, columns, beams, stairs, doors, or windows to populate the read-only preview.
261→            </span>
262→          </div>
263→        )}
264→      </div>
265→
266→      <div className={styles.footer}>
267→        <span>{primaryFooter}</span>
268→        <span>{secondaryFooter}</span>
269→      </div>
270→    </section>
271→  );
272→}
