  1→import * as THREE from 'three';
  2→import { createMaterialPalette, disposeMaterialPalette } from './materials';
  3→import { disposeScene } from './disposeScene';
  4→import { createInspectNavigation } from './createInspectNavigation';
  5→import { createWalkNavigation } from './createWalkNavigation';
  6→import { CLICK_DISTANCE_THRESHOLD } from './previewConfig';
  7→import { createGrid, descriptorBoundsToWorldBox } from './previewCameraMath';
  8→
  9→export function createPreviewViewport(container) {
 10→  const materialPalette = createMaterialPalette();
 11→  const scene = new THREE.Scene();
 12→  scene.background = null;
 13→  const raycaster = new THREE.Raycaster();
 14→  const timer = new THREE.Timer();
 15→  timer.connect(document);
 16→
 17→  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
 18→  const renderer = new THREE.WebGLRenderer({
 19→    antialias: true,
 20→    alpha: true,
 21→    powerPreference: 'high-performance',
 22→  });
 23→  renderer.outputColorSpace = THREE.SRGBColorSpace;
 24→  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
 25→  renderer.setSize(container.clientWidth || 1, container.clientHeight || 1, false);
 26→  renderer.domElement.style.width = '100%';
 27→  renderer.domElement.style.height = '100%';
 28→  renderer.domElement.style.display = 'block';
 29→  container.appendChild(renderer.domElement);
 30→
 31→  const inspectNavigation = createInspectNavigation({
 32→    camera,
 33→    domElement: renderer.domElement,
 34→  });
 35→
 36→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
 37→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
 38→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
 39→  keyLight.position.set(3500, 5000, 2000);
 40→  scene.add(keyLight);
 41→
 42→  let animationFrame = 0;
 43→  let worldRoot = null;
 44→  let gridHelper = null;
 45→  let currentBounds = null;
 46→  let pickHandler = null;
 47→  let pickContext = { activeFloorId: null };
 48→  let pointerDown = null;
 49→  let navigationModifierActive = false;
 50→  let navigationMode = 'inspect';
 51→  let walkUiHandler = null;
 52→  let walkExitHandler = null;
 53→  let compassHeadingHandler = null;
 54→  let inspectState = null;
 55→  let activeFloorContext = {
 56→    floorId: null,
 57→    spawn: null,
 58→  };
 59→  const walkPoseByFloorId = new Map();
 60→  const forwardVector = new THREE.Vector3();
 61→  const horizontalForward = new THREE.Vector3();
 62→  let lastCompassHeading = 0;
 63→  const walkNavigation = createWalkNavigation({
 64→    camera,
 65→    domElement: renderer.domElement,
 66→    onStateChange: () => {
 67→      emitWalkUiState();
 68→    },
 69→    onExitRequested: () => {
 70→      setNavigationMode('inspect');
 71→      walkExitHandler?.();
 72→    },
 73→  });
 74→
 75→  const emitWalkUiState = () => {
 76→    walkUiHandler?.({
 77→      navigationMode,
 78→      isLocked: navigationMode === 'walk' && walkNavigation.isLocked(),
 79→      canLock: navigationMode === 'walk',
 80→    });
 81→  };
 82→
 83→  const emitCompassHeading = () => {
 84→    if (!compassHeadingHandler) return;
 85→
 86→    camera.getWorldDirection(forwardVector);
 87→    horizontalForward.set(forwardVector.x, 0, forwardVector.z);
 88→    if (horizontalForward.lengthSq() > 1e-6) {
 89→      horizontalForward.normalize();
 90→      lastCompassHeading = THREE.MathUtils.radToDeg(
 91→        Math.atan2(horizontalForward.x, -horizontalForward.z)
 92→      );
 93→    }
 94→
 95→    compassHeadingHandler(lastCompassHeading);
 96→  };
 97→
 98→  const saveCurrentWalkPose = () => {
 99→    if (!activeFloorContext.floorId) return;
100→    walkPoseByFloorId.set(activeFloorContext.floorId, walkNavigation.capturePose());
101→  };
102→
103→  const restoreWalkPose = ({ forceSpawn = false } = {}) => {
104→    if (!activeFloorContext.floorId) return;
105→
106→    const rememberedPose = !forceSpawn
107→      ? walkPoseByFloorId.get(activeFloorContext.floorId)
108→      : null;
109→
110→    if (rememberedPose) {
111→      walkNavigation.restorePose(rememberedPose);
112→      return;
113→    }
114→
115→    const spawn = activeFloorContext.spawn;
116→    if (!spawn?.position || !spawn.lookAt) return;
117→
118→    walkNavigation.restorePose({
119→      position: [spawn.position.x, spawn.position.y, spawn.position.z],
120→      lookAt: [spawn.lookAt.x, spawn.lookAt.y, spawn.lookAt.z],
121→    });
122→  };
123→
124→  const setNavigationMode = (nextMode = 'inspect') => {
125→    const resolvedMode = nextMode === 'walk' ? 'walk' : 'inspect';
126→    if (navigationMode === resolvedMode) {
127→      emitWalkUiState();
128→      return;
129→    }
130→
131→    if (navigationMode === 'inspect') {
132→      inspectState = inspectNavigation.captureState();
133→    }
134→
135→    if (navigationMode === 'walk') {
136→      saveCurrentWalkPose();
137→    }
138→
139→    navigationMode = resolvedMode;
140→    inspectNavigation.setEnabled(navigationMode === 'inspect');
141→    walkNavigation.setEnabled(navigationMode === 'walk');
142→
143→    if (navigationMode === 'inspect') {
144→      // Derive inspect state from walk camera so the view doesn't jump
145→      const forward = new THREE.Vector3();
146→      camera.getWorldDirection(forward);
147→      const orbitTarget = camera.position.clone().add(forward.multiplyScalar(3000));
148→      const derived = {
149→        position: camera.position.toArray(),
150→        target: orbitTarget.toArray(),
151→      };
152→      if (!inspectNavigation.restoreState(derived)) {
153→        inspectNavigation.resetView();
154→      }
155→    } else {
156→      restoreWalkPose();
157→    }
158→
159→    emitWalkUiState();
160→  };
161→
162→  const renderFrame = (timestamp) => {
163→    timer.update(timestamp);
164→    const deltaSeconds = Math.min(timer.getDelta(), 0.1);
165→    if (navigationMode === 'inspect') {
166→      inspectNavigation.update(deltaSeconds);
167→    } else {
168→      walkNavigation.update(deltaSeconds);
169→    }
170→    emitCompassHeading();
171→    renderer.render(scene, camera);
172→    animationFrame = window.requestAnimationFrame(renderFrame);
173→  };
174→
175→  const resize = () => {
176→    const width = container.clientWidth || 1;
177→    const height = container.clientHeight || 1;
178→    camera.aspect = width / height;
179→    camera.updateProjectionMatrix();
180→    renderer.setSize(width, height, false);
181→  };
182→
183→  const resolvePickTarget = (object) => {
184→    let current = object;
185→    while (current) {
186→      if (current.userData?.previewTarget) {
187→        return current.userData.previewTarget;
188→      }
189→      current = current.parent;
190→    }
191→    return null;
192→  };
193→
194→  const pickObjectAt = (clientX, clientY) => {
195→    if (navigationMode !== 'inspect') return;
196→    if (!worldRoot || !pickHandler) return;
197→
198→    const rect = renderer.domElement.getBoundingClientRect();
199→    if (!rect.width || !rect.height) return;
200→
201→    const pointer = new THREE.Vector2(
202→      ((clientX - rect.left) / rect.width) * 2 - 1,
203→      -(((clientY - rect.top) / rect.height) * 2 - 1)
204→    );
205→
206→    raycaster.setFromCamera(pointer, camera);
207→    const hits = raycaster.intersectObject(worldRoot, true);
208→    const seenTargets = new Set();
209→    const targets = [];
210→
211→    for (const hit of hits) {
212→      const target = resolvePickTarget(hit.object);
213→      if (!target) continue;
214→
215→      const key = `${target.floorId || ''}:${target.kind}:${target.sourceId}`;
216→      if (seenTargets.has(key)) continue;
217→      seenTargets.add(key);
218→      targets.push(target);
219→    }
220→
221→    if (!targets.length) {
222→      pickHandler(null);
223→      return;
224→    }
225→
226→    const preferredTarget = pickContext.activeFloorId
227→      ? targets.find((target) => target.floorId === pickContext.activeFloorId) || null
228→      : null;
229→
230→    pickHandler(preferredTarget || targets[0]);
231→  };
232→
233→  const handlePointerDown = (event) => {
234→    if (navigationMode !== 'inspect') {
235→      pointerDown = null;
236→      return;
237→    }
238→
239→    if (navigationModifierActive) {
240→      pointerDown = null;
241→      return;
242→    }
243→
244→    if (event.button !== 0) {
245→      pointerDown = null;
246→      return;
247→    }
248→
249→    pointerDown = {
250→      x: event.clientX,
251→      y: event.clientY,
252→    };
253→  };
254→
255→  const handlePointerCancel = () => {
256→    pointerDown = null;
257→  };
258→
259→  const handlePointerUp = (event) => {
260→    if (navigationMode !== 'inspect') {
261→      pointerDown = null;
262→      return;
263→    }
264→
265→    if (navigationModifierActive) {
266→      pointerDown = null;
267→      return;
268→    }
269→
270→    if (event.button !== 0 || !pointerDown) {
271→      pointerDown = null;
272→      return;
273→    }
274→
275→    const dx = event.clientX - pointerDown.x;
276→    const dy = event.clientY - pointerDown.y;
277→    pointerDown = null;
278→
279→    if (Math.hypot(dx, dy) > CLICK_DISTANCE_THRESHOLD) {
280→      return;
281→    }
282→
283→    pickObjectAt(event.clientX, event.clientY);
284→  };
285→
286→  renderer.domElement.addEventListener('pointerdown', handlePointerDown);
287→  renderer.domElement.addEventListener('pointerup', handlePointerUp);
288→  renderer.domElement.addEventListener('pointercancel', handlePointerCancel);
289→  renderer.domElement.addEventListener('pointerleave', handlePointerCancel);
290→
291→  animationFrame = window.requestAnimationFrame(renderFrame);
292→
293→  return {
294→    setWorld(nextRoot, bounds, groundLevel = 0) {
295→      const hadWorld = !!worldRoot;
296→      const walkPose = navigationMode === 'walk' ? walkNavigation.capturePose() : null;
297→
298→      if (worldRoot) {
299→        scene.remove(worldRoot);
300→        disposeScene(worldRoot, { disposeMaterials: true });
301→      }
302→
303→      if (gridHelper) {
304→        scene.remove(gridHelper);
305→        gridHelper.geometry?.dispose?.();
306→        gridHelper.material?.dispose?.();
307→      }
308→
309→      worldRoot = nextRoot;
310→      currentBounds = descriptorBoundsToWorldBox(bounds);
311→      inspectNavigation.setBounds(currentBounds);
312→      gridHelper = createGrid(bounds, groundLevel);
