506→function createFixtureObject(descriptor, materialPalette, isSelected) {
507→  const builder = FIXTURE_BUILDERS[descriptor.fixtureType];
508→  if (!builder) {
509→    return createBoxObject(descriptor, materialPalette, isSelected);
510→  }
511→
512→  const group = new THREE.Group();
513→  const W = descriptor.size.x;
514→  const H = descriptor.size.y;
515→  const D = descriptor.size.z;
516→
517→  builder(group, W, H, D, materialPalette, isSelected);
518→
519→  group.position.copy(planPointToWorld(descriptor.center, descriptor.baseElevation));
520→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
521→
522→  return group;
523→}
524→
525→// ── Railing ──
526→
527→function createRailingObject(descriptor, materialPalette, isSelected) {
528→  const group = new THREE.Group();
529→  const { x: length, y: height, z: width } = descriptor.size;
530→  const railingType = descriptor.railingType || 'handrail';
531→  const railHeight = 50; // handrail tube diameter
532→  const postWidth = 30;
533→
534→  if (railingType === 'glass') {
535→    // Top metal rail
536→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
537→      0, height - railHeight / 2, 0, materialPalette, isSelected);
538→    // Bottom metal rail
539→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
540→      0, railHeight / 2, 0, materialPalette, isSelected);
541→    // Glass panel (full height between rails, no outline for clean look)
542→    const glassH = height - railHeight * 2;
543→    const glassGeo = new THREE.BoxGeometry(
544→      Math.max(length, 1), Math.max(glassH, 1), Math.max(width * 0.3, 1)
545→    );
546→    const glassMesh = new THREE.Mesh(glassGeo,
547→      createMeshMaterial(materialPalette, 'railing_glass', isSelected));
548→    glassMesh.position.set(0, height / 2, 0);
549→    glassMesh.castShadow = false;
550→    glassMesh.receiveShadow = true;
551→    group.add(glassMesh);
552→  } else if (railingType === 'guardrail') {
553→    // Solid opaque panel
554→    addBox(group, 'railing_guardrail', length, height, width,
555→      0, height / 2, 0, materialPalette, isSelected);
556→  } else {
557→    // handrail: top rail + vertical balusters
558→    // Top rail
559→    addBox(group, 'railing_handrail', length, railHeight, postWidth,
560→      0, height - railHeight / 2, 0, materialPalette, isSelected);
561→    // Balusters spaced ~300mm apart
562→    const spacing = 300;
563→    const postCount = Math.max(2, Math.floor(length / spacing) + 1);
564→    const actualSpacing = length / (postCount - 1);
565→    for (let i = 0; i < postCount; i++) {
566→      const px = -length / 2 + i * actualSpacing;
567→      addCylinder(group, 'railing_handrail',
568→        postWidth / 2, postWidth / 2, height - railHeight, 8,
569→        px, (height - railHeight) / 2, 0, materialPalette, isSelected);
570→    }
571→  }
572→
573→  // Position and rotate
574→  const center = planPointToWorld(
575→    descriptor.center,
576→    descriptor.baseElevation
577→  );
578→  group.position.copy(center);
579→  group.rotation.y = planAngleToWorldRotation(descriptor.rotation);
580→
581→  return group;
582→}
