584→// ── Dispatcher ──
585→
586→function createObjectForDescriptor(descriptor, materialPalette, isSelected) {
587→  if (descriptor.geometry === 'prism') {
588→    return createPrismObject(descriptor, materialPalette, isSelected);
589→  }
590→
591→  if (descriptor.geometry === 'roofMesh') {
592→    return createRoofMeshObject(descriptor, materialPalette, isSelected);
593→  }
594→
595→  if (descriptor.geometry === 'stair') {
596→    return createStairObject(descriptor, materialPalette, isSelected);
597→  }
598→
599→  if (descriptor.geometry === 'segment3d') {
600→    return createSegment3DObject(descriptor, materialPalette, isSelected);
601→  }
602→
603→  if (descriptor.geometry === 'window') {
604→    return createWindowObject(descriptor, materialPalette, isSelected);
605→  }
606→
607→  if (descriptor.geometry === 'railing') {
608→    return createRailingObject(descriptor, materialPalette, isSelected);
609→  }
610→
611→  if (descriptor.geometry === 'fixture') {
612→    return createFixtureObject(descriptor, materialPalette, isSelected);
613→  }
614→
615→  return createBoxObject(descriptor, materialPalette, isSelected);
616→}
617→
618→function matchesSelection(descriptor, selection) {
619→  if (!selection?.selectedId) return false;
620→  if (selection.selectedType === 'trussSystem') {
621→    return descriptor.metadata?.trussSystemId === selection.selectedId;
622→  }
623→  if (selection.selectedType !== descriptor.kind) return false;
624→  return (descriptor.metadata?.sourceId || descriptor.id) === selection.selectedId;
625→}
626→
627→function assignPreviewMetadata(object, descriptor, floor) {
628→  const previewTarget = {
629→    kind: descriptor.kind,
630→    sourceId: descriptor.metadata?.sourceId || descriptor.id,
631→    floorId: descriptor.metadata?.floorId || floor.floorId,
632→  };
633→
634→  object.traverse((node) => {
635→    node.userData = {
636→      ...node.userData,
637→      previewTarget,
638→    };
639→  });
640→}
641→
642→export function buildPreviewObjectRoot(sceneDescriptor, materialPalette, selection = null) {
643→  const root = new THREE.Group();
644→  root.name = 'preview-root';
645→
646→  for (const floor of sceneDescriptor.floors) {
647→    const floorGroup = new THREE.Group();
648→    floorGroup.name = `floor-${floor.floorId}`;
649→    floorGroup.visible = floor.visible;
650→    floorGroup.userData = {
651→      floorId: floor.floorId,
652→      floorName: floor.name,
653→      elevation: floor.elevation,
654→    };
655→
656→    for (const descriptor of floor.objects) {
657→      const isSelected = matchesSelection(descriptor, selection);
658→      const object = createObjectForDescriptor(descriptor, materialPalette, isSelected);
659→      object.name = descriptor.id;
660→      object.userData = {
661→        id: descriptor.id,
662→        kind: descriptor.kind,
663→        metadata: descriptor.metadata,
664→      };
665→      assignPreviewMetadata(object, descriptor, floor);
666→      floorGroup.add(object);
667→    }
668→
669→    root.add(floorGroup);
670→  }
671→
672→  return root;
673→}
