27→export function add(a, b) {
28→  return { x: a.x + b.x, y: a.y + b.y };
29→}
30→
31→export function subtract(a, b) {
32→  return { x: a.x - b.x, y: a.y - b.y };
33→}
34→
35→export function scale(p, s) {
36→  return { x: p.x * s, y: p.y * s };
37→}
