 1→import { createRoom } from '@/domain/models';
 2→import { findRoomFaceAtPoint, roomPolygonKey } from '@/geometry/roomDetection';
 3→
 4→function findExistingRoomForFace(rooms, face) {
 5→  if (!face) return null;
 6→  return rooms.find(room => roomPolygonKey(room.points) === face.key) || null;
 7→}
 8→
 9→export function createRoomPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, activePhaseId }) {
10→  return {
11→    onMouseDown(modelPos, e) {
12→      if (e.button !== 0) return;
13→
14→      const floor = getFloor(activeFloorId);
15→      if (!floor) return;
16→
17→      const face = findRoomFaceAtPoint(floor.walls, floor.columns || [], modelPos);
18→      if (!face) {
19→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'No enclosed room found here.' });
20→        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { previewPoints: null } });
21→        return;
22→      }
23→
24→      const existingRoom = findExistingRoomForFace(floor.rooms, face);
25→      if (existingRoom) {
26→        editorDispatch({ type: 'SELECT_OBJECT', id: existingRoom.id, objectType: 'room' });
27→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'A room already exists in this space.' });
28→        return;
29→      }
30→
31→      const room = createRoom(`Room ${floor.rooms.length + 1}`, face.points);
32→      room.phaseId = activePhaseId || null;
33→      dispatch({ type: 'ROOM_ADD', floorId: activeFloorId, room });
34→      editorDispatch({ type: 'SELECT_OBJECT', id: room.id, objectType: 'room' });
35→      editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { previewPoints: face.points } });
36→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `Created ${room.name}.` });
37→    },
38→
39→    onMouseMove(modelPos) {
40→      const floor = getFloor(activeFloorId);
41→      if (!floor) return;
42→
43→      const face = findRoomFaceAtPoint(floor.walls, floor.columns || [], modelPos);
44→      const previewPoints = face && !findExistingRoomForFace(floor.rooms, face)
45→        ? face.points
46→        : null;
47→
48→      editorDispatch({
49→        type: 'UPDATE_TOOL_STATE',
50→        payload: { previewPoints },
51→      });
52→    },
53→
54→    onKeyDown(e) {
55→      if (e.key !== 'Escape') return;
56→      editorDispatch({
57→        type: 'UPDATE_TOOL_STATE',
58→        payload: { previewPoints: null },
59→      });
60→    },
61→
62→    getCursor() {
63→      return 'crosshair';
64→    },
65→  };
66→}
