  2→ * Drawing plane geometry - pure functions, no React/Three.js dependencies.
  3→ * A drawing plane defines a 2D coordinate system embedded in 3D space.
  4→ */
  5→
  6→import { getPartDimensions } from './partGeometry';
  7→import { getSolidPlane } from './solidGeometry';
  8→
  9→/** Ground plane at Z=0 (domain coords: XY plane) */
 10→export const GROUND_PLANE = Object.freeze({
 11→  origin: { x: 0, y: 0, z: 0 },
 12→  normal: { x: 0, y: 0, z: 1 },
 13→  up: { x: 0, y: 1, z: 0 },
 14→  uAxis: { x: 1, y: 0, z: 0 },
 15→  vAxis: { x: 0, y: 1, z: 0 },
 16→  sourcePartId: null,
 17→  sourceFace: null,
 18→});
 19→
 20→/**
 21→ * Given a part and a face ID, compute a drawing plane sitting on that face.
 22→ * Face IDs: '+x', '-x', '+y', '-y', '+z', '-z'
 23→ */
 24→export function faceToDrawingPlane(part, faceId) {
 25→  if (part.type === 'solid') {
 26→    const solidPlane = getSolidPlane(part);
 27→    const depth = Number.isFinite(part.extrusionDepth) ? part.extrusionDepth : 120;
 28→    const normalFace = (
 29→      Math.abs(solidPlane.normal.x) > 0.9
 30→        ? (solidPlane.normal.x >= 0 ? '+x' : '-x')
 31→        : Math.abs(solidPlane.normal.y) > 0.9
 32→          ? (solidPlane.normal.y >= 0 ? '+y' : '-y')
 33→          : (solidPlane.normal.z >= 0 ? '+z' : '-z')
 34→    );
 35→    const oppositeFace = normalFace.startsWith('+')
 36→      ? `-${normalFace.slice(1)}`
 37→      : `+${normalFace.slice(1)}`;
 38→
 39→    if (faceId === normalFace || faceId === oppositeFace) {
 40→      return {
 41→        origin: faceId === normalFace
 42→          ? {
 43→              x: solidPlane.origin.x + solidPlane.normal.x * depth,
 44→              y: solidPlane.origin.y + solidPlane.normal.y * depth,
 45→              z: solidPlane.origin.z + solidPlane.normal.z * depth,
 46→            }
 47→          : solidPlane.origin,
 48→        normal: solidPlane.normal,
 49→        up: solidPlane.up,
 50→        uAxis: solidPlane.uAxis,
 51→        vAxis: solidPlane.vAxis,
 52→        sourcePartId: part.id,
 53→        sourceFace: faceId,
 54→      };
 55→    }
 56→  }
 57→
 58→  const { position } = part;
 59→  const dims = getPartDimensions(part);
 60→
 61→  // Center of the part in domain coords
 62→  const cx = position.x + dims.width / 2;
 63→  const cy = position.y + dims.depth / 2;
 64→  const cz = position.z + dims.height / 2;
 65→
 66→  let origin, normal, up, uAxis, vAxis;
 67→
 68→  switch (faceId) {
 69→    case '+z': // top face
 70→      origin = { x: position.x, y: position.y, z: position.z + dims.height };
 71→      normal = { x: 0, y: 0, z: 1 };
 72→      uAxis = { x: 1, y: 0, z: 0 };
 73→      vAxis = { x: 0, y: 1, z: 0 };
 74→      up = { x: 0, y: 1, z: 0 };
 75→      break;
 76→    case '-z': // bottom face
 77→      origin = { x: position.x, y: position.y, z: position.z };
 78→      normal = { x: 0, y: 0, z: -1 };
 79→      uAxis = { x: 1, y: 0, z: 0 };
 80→      vAxis = { x: 0, y: 1, z: 0 };
 81→      up = { x: 0, y: 1, z: 0 };
 82→      break;
 83→    case '+x': // right face
 84→      origin = { x: position.x + dims.width, y: position.y, z: position.z };
 85→      normal = { x: 1, y: 0, z: 0 };
 86→      uAxis = { x: 0, y: 1, z: 0 };
 87→      vAxis = { x: 0, y: 0, z: 1 };
 88→      up = { x: 0, y: 0, z: 1 };
 89→      break;
 90→    case '-x': // left face
 91→      origin = { x: position.x, y: position.y, z: position.z };
 92→      normal = { x: -1, y: 0, z: 0 };
 93→      uAxis = { x: 0, y: 1, z: 0 };
 94→      vAxis = { x: 0, y: 0, z: 1 };
 95→      up = { x: 0, y: 0, z: 1 };
 96→      break;
 97→    case '+y': // back face
 98→      origin = { x: position.x, y: position.y + dims.depth, z: position.z };
 99→      normal = { x: 0, y: 1, z: 0 };
100→      uAxis = { x: 1, y: 0, z: 0 };
101→      vAxis = { x: 0, y: 0, z: 1 };
102→      up = { x: 0, y: 0, z: 1 };
103→      break;
104→    case '-y': // front face
105→      origin = { x: position.x, y: position.y, z: position.z };
106→      normal = { x: 0, y: -1, z: 0 };
107→      uAxis = { x: 1, y: 0, z: 0 };
108→      vAxis = { x: 0, y: 0, z: 1 };
109→      up = { x: 0, y: 0, z: 1 };
110→      break;
111→    default:
112→      return { ...GROUND_PLANE };
113→  }
114→
115→  return { origin, normal, up, uAxis, vAxis, sourcePartId: part.id, sourceFace: faceId };
116→}
