 16→  const candidate = cloneVector(vector, fallback);
 17→  const length = Math.hypot(candidate.x, candidate.y, candidate.z) || 1;
 18→  return {
 19→    x: candidate.x / length,
 20→    y: candidate.y / length,
 21→    z: candidate.z / length,
 22→  };
 23→}
