 25→function dedupeProfilePoints(points) {
 26→  const normalized = [];
 27→  for (const point of points || []) {
 28→    const candidate = {
 29→      u: Number.isFinite(point?.u) ? point.u : 0,
 30→      v: Number.isFinite(point?.v) ? point.v : 0,
 31→    };
 32→    const previous = normalized[normalized.length - 1];
 33→    if (previous && Math.hypot(candidate.u - previous.u, candidate.v - previous.v) < 0.001) {
 34→      continue;
 35→    }
 36→    normalized.push(candidate);
 37→  }
 38→
 39→  if (normalized.length > 2) {
 40→    const first = normalized[0];
 41→    const last = normalized[normalized.length - 1];
 42→    if (Math.hypot(first.u - last.u, first.v - last.v) < 0.001) {
 43→      normalized.pop();
 44→    }
 45→  }
 46→
 47→  return normalized;
 48→}
