 68→      y: Number.isFinite(part?.position?.y) ? part.position.y : 0,
 69→      z: Number.isFinite(part?.position?.z) ? part.position.z : 0,
 70→    },
 71→    ...clonePlaneDefinition(part?.plane),
 72→  };
 73→}
