  8→/**
  9→ * Face index mapping for BoxGeometry.
 10→ * Three.js BoxGeometry has 6 groups (2 triangles each):
 11→ * group 0: +x, group 1: -x, group 2: +y, group 3: -y, group 4: +z, group 5: -z
 12→ */
 13→const BOX_FACE_IDS = ['+x', '-x', '+y', '-y', '+z', '-z'];
 14→
 15→function createBoxMesh(width, height, depth, color) {
 16→  const geometry = new THREE.BoxGeometry(width, height, depth);
 17→  const material = new THREE.MeshStandardMaterial({
 18→    color,
 19→    roughness: 0.7,
 20→    metalness: 0.05,
 21→  });
 22→  const mesh = new THREE.Mesh(geometry, material);
 23→  mesh.userData.faceIds = BOX_FACE_IDS;
 24→  return mesh;
 25→}
 26→
 27→function createCylinderMesh(diameter, height, color) {
 28→  const geometry = new THREE.CylinderGeometry(diameter / 2, diameter / 2, height, 16);
 29→  const material = new THREE.MeshStandardMaterial({
 30→    color,
 31→    roughness: 0.7,
 32→    metalness: 0.05,
 33→  });
 34→  return new THREE.Mesh(geometry, material);
 35→}
 36→
 37→function addEdges(mesh) {
 38→  const edges = new THREE.EdgesGeometry(mesh.geometry);
 39→  const line = new THREE.LineSegments(
 40→    edges,
 41→    new THREE.LineBasicMaterial({ color: EDGE_COLOR, transparent: true, opacity: 0.3 })
 42→  );
 43→  mesh.add(line);
 44→}
