 46→function domainPointToThree(point) {
 47→  return new THREE.Vector3(point.x, point.z, point.y);
 48→}
 49→
 50→function domainVectorToThree(vector) {
 51→  return new THREE.Vector3(vector.x, vector.z, vector.y);
 52→}
