366→export function getPreviewInspection(project, selectedType, selectedId) {
367→  if (!selectedId || !isPreviewInspectableType(selectedType)) return null;
368→
369→  for (const floor of project?.floors || []) {
370→    const object = findObjectInFloor(floor, selectedType, selectedId);
371→    if (!object) continue;
372→
373→    return {
374→      id: selectedId,
375→      type: selectedType,
376→      floorId: floor.id,
377→      floorName: floor.name,
378→      title: titleForObject(selectedType, object, floor),
379→      subtitle: `${floor.name} · ${TYPE_LABELS[selectedType]}`,
380→      rows: rowsForObject(selectedType, object, floor, project?.roofSystem || null),
381→    };
382→  }
383→
384→  const roofObject = findObjectInRoof(project?.roofSystem, selectedType, selectedId);
385→  if (roofObject) {
386→    const topFloor = getOrderedFloors(project).slice(-1)[0] || null;
387→
388→    return {
389→      id: selectedId,
390→      type: selectedType,
391→      floorId: topFloor?.id || null,
392→      floorName: project?.roofSystem?.name || 'Roof',
393→      title: titleForObject(selectedType, roofObject, topFloor || { columns: [] }),
394→      subtitle: `${project?.roofSystem?.name || 'Roof'} · ${TYPE_LABELS[selectedType]}`,
395→      rows: rowsForObject(selectedType, roofObject, topFloor || { columns: [] }, project?.roofSystem || null),
396→    };
397→  }
398→
399→  const trussObject = findObjectInTrusses(project, selectedType, selectedId);
400→  if (trussObject?.trussSystem) {
401→    const floor = (project?.floors || []).find((entry) => entry.id === trussObject.trussSystem.floorId) || null;
402→    const object = trussObject.trussInstance || trussObject.trussSystem;
403→
404→    return {
405→      id: selectedId,
406→      type: selectedType,
407→      floorId: trussObject.trussSystem.floorId,
408→      floorName: floor?.name || 'Truss',
409→      title: titleForObject(selectedType, object, floor || { columns: [] }),
410→      subtitle: `${trussObject.trussSystem.name || 'Truss System'} · ${TYPE_LABELS[selectedType]}`,
411→      rows: rowsForObject(selectedType, object, floor || { columns: [] }, project?.roofSystem || null),
412→    };
413→  }
414→
415→  return null;
416→}
