16→export function createSlabPlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, activePhaseId }) {
17→  function commitSlab(points) {
18→    const floor = getFloor(activeFloorId);
19→    if (!floor || points.length < 3) return;
20→
21→    const slab = createSlab(floor.id, points, undefined, getFloorElevation(floor));
22→    slab.phaseId = activePhaseId || null;
23→    dispatch({ type: 'SLAB_ADD', floorId: activeFloorId, slab });
24→    editorDispatch({ type: 'SELECT_OBJECT', id: slab.id, objectType: 'slab' });
25→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Created slab.' });
26→
27→    resetSlabToolState(editorDispatch);
28→  }
29→
30→  return {
31→    onMouseDown(modelPos, e, toolState) {
32→      if (e.button !== 0) return;
33→
34→      const floor = getFloor(activeFloorId);
35→      if (!floor) return;
36→
37→      const points = toolState.slabPoints || [];
38→      const closeDistance = SNAP_DISTANCE_PX / viewport.zoom;
39→
40→      if (points.length === 0) {
41→        editorDispatch({
42→          type: 'UPDATE_TOOL_STATE',
43→          payload: {
44→            slabPoints: [{ x: modelPos.x, y: modelPos.y }],
45→            slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
46→          },
47→        });
48→        return;
49→      }
50→
51→      if (points.length >= 3 && distance(modelPos, points[0]) <= closeDistance) {
52→        commitSlab(points);
53→        return;
54→      }
55→
56→      editorDispatch({
57→        type: 'UPDATE_TOOL_STATE',
58→        payload: {
59→          slabPoints: [...points, { x: modelPos.x, y: modelPos.y }],
60→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
61→        },
62→      });
63→    },
64→
65→    onMouseMove(modelPos, e, toolState) {
66→      if (!(toolState.slabPoints || []).length) return;
67→      editorDispatch({
68→        type: 'UPDATE_TOOL_STATE',
69→        payload: {
70→          slabPreviewPoint: { x: modelPos.x, y: modelPos.y },
71→        },
72→      });
73→    },
74→
75→    onDoubleClick(modelPos, e, toolState) {
76→      const points = toolState.slabPoints || [];
77→      if (points.length < 3) return;
78→      commitSlab(points);
79→    },
80→
81→    onKeyDown(e) {
82→      if (e.key !== 'Escape') return;
83→      resetSlabToolState(editorDispatch);
84→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
85→    },
86→
87→    getCursor(toolState) {
88→      return (toolState.slabPoints || []).length ? 'crosshair' : 'crosshair';
89→    },
90→  };
91→}
