 31→  const inferenceCacheRef = useRef(null);
 32→  const resizeObserverRef = useRef(null);
 33→  const compassNeedleRef = useRef(null);
 34→  const movementPlaneRef = useRef(null);
 35→  const pointerDownRef = useRef(null);
 36→  const navigationModifierRef = useRef(false);
 37→  const moveModifierRef = useRef(false);
 38→  const moveDragRoutingRef = useRef(false);
 39→
 40→  const { project, dispatch } = useSketch();
 41→  const {
 42→    activeTool, selectedId, selectedType, toolState,
