 59→    [project, selectedId, selectedType]
 60→  );
 61→  const toolInteractionActive = !!(
 62→    toolState.dragging
 63→    || toolState.drawing
 64→    || toolState.drawingProfile
 65→    || toolState.extruding
 66→  );
 67→
