125→
126→    if ('ResizeObserver' in window) {
127→      const observer = new ResizeObserver(() => viewport.resize());
128→      observer.observe(container);
129→      resizeObserverRef.current = observer;
130→    }
131→
132→    viewport.setCompassHeadingHandler((headingDeg) => {
133→      if (!compassNeedleRef.current) return;
