241→          type: 'UPDATE_TOOL_STATE',
242→          payload: {
243→            dragging: false,
244→            startPoint: null,
245→            dragPartId: null,
246→            dragAssemblyId: null,
247→            dragObjectId: null,
248→            snapResult: null,
249→          },
