277→    // Add overlay groups to root
278→    if (overlayRef.current) {
279→      root.add(overlayRef.current.group);
280→    }
281→    if (extrusionPreviewRef.current) {
282→      root.add(extrusionPreviewRef.current.group);
283→    }
284→    if (snapOverlayRef.current) {
285→      root.add(snapOverlayRef.current.group);
286→    }
287→
288→    const box = new THREE.Box3();
289→    root.updateMatrixWorld(true);
290→    box.expandByObject(root);
291→
292→    if (box.isEmpty()) {
293→      box.set(
294→        new THREE.Vector3(-500, 0, -300),
295→        new THREE.Vector3(500, 800, 300)
296→      );
297→    }
298→
299→    viewport.setWorld(root, {
300→      min: { x: box.min.x, y: box.min.y, z: box.min.z },
301→      max: { x: box.max.x, y: box.max.y, z: box.max.z },
302→    }, 0);
303→  }, [visibleParts, selectedId, selectedType]);
304→
305→  // Update drawing plane overlay
306→  useEffect(() => {
307→    const overlay = overlayRef.current;
308→    if (!overlay) return;
309→
310→    const plane = drawingPlane || GROUND_PLANE;
311→    const isDrawTool = ['solid', 'panel', 'leg', 'frame'].includes(activeTool);
312→
313→    if (isDrawTool) {
314→      overlay.setPlane(plane, 50, 2000);
315→    } else {
316→      overlay.clearGrid();
317→    }
318→  }, [drawingPlane, activeTool]);
319→
320→  // Update drawing preview
321→  useEffect(() => {
322→    const overlay = overlayRef.current;
323→    if (!overlay) return;
324→
325→    if (toolState.drawingProfile && (toolState.profilePoints || []).length > 0) {
326→      const plane = drawingPlane || GROUND_PLANE;
327→      overlay.setPreviewPolygon(plane, toolState.profilePoints, toolState.currentLocal);
328→    } else if (toolState.drawing && toolState.startLocal && toolState.currentLocal) {
329→      const plane = drawingPlane || GROUND_PLANE;
330→      overlay.setPreviewRect(plane, toolState.startLocal, toolState.currentLocal);
331→    } else {
332→      overlay.clearPreview();
333→    }
334→  }, [toolState.drawingProfile, toolState.profilePoints, toolState.drawing, toolState.startLocal, toolState.currentLocal, drawingPlane]);
335→
336→  // Update extrusion preview
337→  useEffect(() => {
338→    const preview = extrusionPreviewRef.current;
339→    if (!preview) return;
340→
341→    if (toolState.extruding && toolState.sourcePart && toolState.faceId) {
342→      preview.update(toolState.sourcePart, toolState.faceId, toolState.extrusionDistance || 0);
343→    } else {
344→      preview.clear();
345→    }
346→  }, [toolState.extruding, toolState.sourcePart, toolState.faceId, toolState.extrusionDistance]);
347→
348→  // Update snap overlay from toolState
349→  useEffect(() => {
350→    const snapOvl = snapOverlayRef.current;
351→    if (!snapOvl) return;
352→
353→    if (toolState.snapResult && snapEnabled) {
354→      snapOvl.updateSnapIndicator(toolState.snapResult);
355→    } else {
356→      snapOvl.updateSnapIndicator(null);
357→    }
358→  }, [toolState.snapResult, snapEnabled]);
359→
360→  // Update face hover highlight from toolState
361→  useEffect(() => {
362→    const snapOvl = snapOverlayRef.current;
363→    if (!snapOvl) return;
364→
365→    if (toolState.hoverPartId && toolState.hoverFaceId && snapEnabled) {
366→      const part = project.parts.find((p) => p.id === toolState.hoverPartId);
367→      snapOvl.updateHoverFace(part, toolState.hoverFaceId);
368→    } else {
369→      snapOvl.updateHoverFace(null, null);
370→    }
371→  }, [toolState.hoverPartId, toolState.hoverFaceId, snapEnabled, project.parts]);
372→
373→  // Raycasting helper
374→  const raycast = useCallback((e) => {
375→    const viewport = viewportRef.current;
376→    if (!viewport || !rootRef.current) return null;
377→
378→    const renderer = viewport.getDomElement?.();
379→    const camera = viewport.getCamera?.();
380→    if (!renderer || !camera) return null;
381→
382→    const rect = renderer.getBoundingClientRect();
383→    if (!rect.width || !rect.height) return null;
384→
385→    const pointer = new THREE.Vector2(
386→      ((e.clientX - rect.left) / rect.width) * 2 - 1,
387→      -(((e.clientY - rect.top) / rect.height) * 2 - 1)
388→    );
389→
390→    const raycaster = new THREE.Raycaster();
391→    raycaster.setFromCamera(pointer, camera);
392→
393→    // Raycast against world objects (excluding overlay groups)
394→    const hits = raycaster.intersectObject(rootRef.current, true);
395→
396→    let partId = null;
397→    let objectId = null;
398→    let point = null;
399→    let faceNormal = null;
400→
401→    for (const hit of hits) {
402→      // Skip overlay objects
403→      if (isOverlayObject(hit.object)) continue;
404→
405→      point = { x: hit.point.x, y: hit.point.y, z: hit.point.z };
406→
407→      // Get face normal
408→      if (hit.face) {
409→        const normal = hit.face.normal.clone();
410→        hit.object.updateMatrixWorld();
411→        const normalMatrix = new THREE.Matrix3().getNormalMatrix(hit.object.matrixWorld);
412→        normal.applyMatrix3(normalMatrix).normalize();
413→        faceNormal = { x: normal.x, y: normal.y, z: normal.z };
414→      }
415→
416→      // Resolve to part/object
417→      const target = resolvePickTarget(hit.object);
418→      if (target) {
419→        if (target.kind === 'part') {
420→          partId = target.sourceId;
421→        } else if (target.kind === 'object') {
422→          objectId = target.sourceId;
423→          // Also find a part for the hit
424→          partId = findPartIdFromObjectHit(hit.object, project);
425→        }
426→        break;
427→      }
428→    }
429→
430→    // Compute drawing plane intersection
431→    const plane = drawingPlane || GROUND_PLANE;
432→    const threePlane = domainPlaneToThreePlane(plane);
433→    const drawingPlanePoint3 = new THREE.Vector3();
434→    const hasPlaneHit = raycaster.ray.intersectPlane(threePlane, drawingPlanePoint3);
435→    const drawingPlanePoint = hasPlaneHit
436→      ? { x: drawingPlanePoint3.x, y: drawingPlanePoint3.z, z: drawingPlanePoint3.y } // Three.js -> domain
437→      : null;
438→
439→    // Compute movement plane (camera-perpendicular through drag start or hit point)
440→    const movementOrigin = point || (hasPlaneHit ? { x: drawingPlanePoint3.x, y: drawingPlanePoint3.y, z: drawingPlanePoint3.z } : null);
441→    let planePoint = null;
442→    if (movementOrigin && movementPlaneRef.current) {
443→      const mvPoint = new THREE.Vector3();
444→      if (raycaster.ray.intersectPlane(movementPlaneRef.current, mvPoint)) {
445→        planePoint = { x: mvPoint.x, y: mvPoint.y, z: mvPoint.z };
446→      }
447→    }
448→
449→    // Update cursor coords (convert Three.js -> domain: x=x, y=z, z=y)
450→    if (point) {
451→      setCursorCoords({
452→        x: Math.round(point.x),
453→        y: Math.round(point.z), // Three.js Z = domain Y
454→        z: Math.round(point.y), // Three.js Y = domain Z
455→      });
456→    } else if (drawingPlanePoint) {
457→      setCursorCoords({
458→        x: Math.round(drawingPlanePoint.x),
459→        y: Math.round(drawingPlanePoint.y),
460→        z: Math.round(drawingPlanePoint.z),
461→      });
462→    }
463→
464→    return { partId, objectId, point, faceNormal, drawingPlanePoint, planePoint };
465→  }, [project, drawingPlane]);
466→
467→  // Set up movement plane when drag starts
468→  useEffect(() => {
469→    if (toolState.dragging && toolState.startPoint) {
470→      const viewport = viewportRef.current;
471→      const camera = viewport?.getCamera?.();
472→      if (camera) {
473→        const camDir = new THREE.Vector3();
474→        camera.getWorldDirection(camDir);
475→        const origin = new THREE.Vector3(toolState.startPoint.x, toolState.startPoint.y, toolState.startPoint.z);
476→        movementPlaneRef.current = new THREE.Plane().setFromNormalAndCoplanarPoint(camDir, origin);
477→      }
478→    } else if (!toolState.dragging) {
479→      movementPlaneRef.current = null;
480→    }
481→  }, [toolState.dragging, toolState.startPoint]);
482→
483→  const shouldRouteCtrlMove = useCallback((event) => {
484→    if (navigationModifierRef.current) return false;
485→    if (moveDragRoutingRef.current) return true;
486→    if (!(event?.ctrlKey || moveModifierRef.current)) return false;
487→    return !toolInteractionActive;
488→  }, [toolInteractionActive]);
489→
490→  // Pointer event handlers
491→  const handlePointerDown = useCallback((e) => {
492→    // Right-click and middle-click are handled by OrbitControls
493→    if (e.button !== 0) return;
494→    if (navigationModifierRef.current) {
495→      pointerDownRef.current = null;
496→      return;
497→    }
498→
499→    pointerDownRef.current = { x: e.clientX, y: e.clientY };
500→
501→    const intersection = raycast(e);
502→    if (!intersection) return;
503→    const activePointerTool = shouldRouteCtrlMove(e) ? moveTool : tool;
504→    moveDragRoutingRef.current = activePointerTool === moveTool;
505→
506→    // Set up movement plane for drag
507→    if (intersection.point) {
508→      const viewport = viewportRef.current;
509→      const camera = viewport?.getCamera?.();
510→      if (camera) {
511→        const camDir = new THREE.Vector3();
512→        camera.getWorldDirection(camDir);
513→        const origin = new THREE.Vector3(intersection.point.x, intersection.point.y, intersection.point.z);
514→        movementPlaneRef.current = new THREE.Plane().setFromNormalAndCoplanarPoint(camDir, origin);
515→      }
516→    }
517→
518→    activePointerTool.onPointerDown(intersection, e, toolState, viewportRef.current);
519→  }, [raycast, tool, moveTool, toolState, shouldRouteCtrlMove]);
520→
521→  const handlePointerMove = useCallback((e) => {
522→    if (navigationModifierRef.current) return;
523→
524→    const isActive = toolInteractionActive || moveDragRoutingRef.current;
525→    const activePointerTool = moveDragRoutingRef.current || shouldRouteCtrlMove(e) ? moveTool : tool;
526→
527→    // Always raycast for hover/snap feedback (even when idle)
528→    if (e.buttons === 0 && !isActive) {
529→      // Idle hover — call onHover for snap preview
530→      if (activePointerTool.onHover && snapEnabled) {
531→        const intersection = raycast(e);
532→        if (intersection) {
533→          activePointerTool.onHover(intersection, e, toolState, viewportRef.current);
534→        }
535→      }
536→      return;
537→    }
538→
539→    const intersection = raycast(e);
540→    if (!intersection) return;
541→
542→    activePointerTool.onPointerMove(intersection, e, toolState, viewportRef.current);
543→  }, [raycast, tool, moveTool, toolInteractionActive, toolState, snapEnabled, shouldRouteCtrlMove]);
544→
545→  const handlePointerUp = useCallback((e) => {
546→    if (e.button !== 0) return;
547→    if (navigationModifierRef.current) {
548→      pointerDownRef.current = null;
549→      return;
550→    }
551→
552→    // Check if this was a click vs drag (for OrbitControls compatibility)
553→    const down = pointerDownRef.current;
554→    pointerDownRef.current = null;
555→
556→    if (down) {
557→      const dx = e.clientX - down.x;
558→      const dy = e.clientY - down.y;
559→      if (Math.hypot(dx, dy) > 5 && !toolState.dragging && !toolState.drawing && !toolState.drawingProfile && !toolState.extruding) {
560→        // Was an orbit gesture, not a tool interaction
561→        moveDragRoutingRef.current = false;
562→        return;
563→      }
564→    }
565→
566→    const intersection = raycast(e);
567→    const activePointerTool = moveDragRoutingRef.current || shouldRouteCtrlMove(e) ? moveTool : tool;
568→    activePointerTool.onPointerUp(intersection, e, toolState, viewportRef.current);
569→    moveDragRoutingRef.current = false;
570→  }, [raycast, tool, moveTool, toolState, shouldRouteCtrlMove]);
571→
572→  const handleDoubleClick = useCallback((e) => {
573→    if (navigationModifierRef.current) return;
574→    const intersection = raycast(e);
575→    if (intersection && tool.onDoubleClick) {
576→      tool.onDoubleClick(intersection, e, toolState);
577→    }
578→  }, [raycast, tool, toolState]);
579→
580→  // Keyboard shortcuts
581→  useEffect(() => {
582→    const handleKeyDown = (e) => {
583→      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA' || e.target.isContentEditable) return;
584→      if (e.code === 'Space') return;
585→
586→      if (e.key === 'Escape') {
587→        if (activeAssemblyId) {
588→          tool.onKeyDown(e, toolState, selectedId);
589→          return;
590→        }
591→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
