597→        if (toolKey) {
598→          editorDispatch({ type: 'SET_TOOL', tool: toolKey });
599→          return;
600→        }
601→
602→        // Push/pull shortcut
603→        if (e.key.toLowerCase() === 'e') {
604→          editorDispatch({ type: 'SET_TOOL', tool: 'pushpull' });
605→          return;
606→        }
607→      }
608→
609→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
