641→    : null;
642→
643→  const extrusionLabel = toolState.extruding && toolState.extrusionDistance
644→    ? `${Math.round(toolState.extrusionDistance)} mm`
645→    : null;
646→
647→  // Snap type indicator
648→  const snapTypeLabel = toolState.snapResult?.inference?.type || null;
649→
650→  const hasParts = project.parts.length > 0;
651→  const hasAssemblies = project.assemblies.length > 0;
652→  const showEmptyState = !hasParts && !hasAssemblies && !emptyStateDismissed;
653→  const isComponentPlacementTool = ['panel', 'leg', 'frame'].includes(activeTool);
