837→function isOverlayObject(obj) {
838→  let current = obj;
839→  while (current) {
840→    if (current.name === 'DrawingPlaneOverlay' || current.name === 'ExtrusionPreview' ||
841→        current.name === 'PlaneGrid' || current.name === 'DrawPreview' ||
842→        current.name === 'SnapOverlay' || current.name === 'AlignmentGuides') {
843→      return true;
844→    }
845→    current = current.parent;
846→  }
847→  return false;
848→}
849→
850→function resolvePickTarget(object) {
851→  let current = object;
852→  while (current) {
853→    if (current.userData?.previewTarget) {
854→      return current.userData.previewTarget;
855→    }
856→    current = current.parent;
857→  }
858→  return null;
859→}
860→
861→function findPartIdFromObjectHit(object, project) {
862→  const target = resolvePickTarget(object);
863→  if (!target) return null;
864→  if (target.kind === 'part') return target.sourceId;
865→
866→  // Object hit - find first matching part
867→  const part = project.parts.find((p) => p.objectId === target.sourceId && p.type !== 'dimension' && p.type !== 'cutout' && p.type !== 'hole');
868→  return part?.id || null;
869→}
