871→/**
872→ * Convert a domain drawing plane to a Three.js Plane.
873→ * Domain: x=x, y=y, z=z -> Three.js: x=x, y=z, z=y
874→ */
875→function domainPlaneToThreePlane(plane) {
876→  const threeNormal = new THREE.Vector3(
877→    plane.normal.x,
878→    plane.normal.z, // domain Z -> Three.js Y
879→    plane.normal.y  // domain Y -> Three.js Z
880→  ).normalize();
881→
882→  const threeOrigin = new THREE.Vector3(
883→    plane.origin.x,
884→    plane.origin.z, // domain Z -> Three.js Y
885→    plane.origin.y  // domain Y -> Three.js Z
886→  );
887→
888→  return new THREE.Plane().setFromNormalAndCoplanarPoint(threeNormal, threeOrigin);
889→}
