  1→import * as THREE from 'three';
  2→import { snapToGrid, smartSnap3d } from '../snap';
  3→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  4→import { faceToDrawingPlane, identifyFace, GROUND_PLANE } from '../../domain/drawingPlane';
  5→
  6→/**
  7→ * 3D select/move handler.
  8→ * Left-click to select, drag to move on a camera-perpendicular plane.
  9→ */
 10→export function createSelectHandler3d({ dispatch, editorDispatch, project, activeAssemblyId, snapEnabled, selectedId, selectedType, inferenceCache }) {
 11→  const isEditMode = activeAssemblyId !== null;
 12→
 13→  return {
 14→    onPointerDown(intersection, e, toolState, viewport) {
 15→      if (e.button !== 0) return;
 16→
 17→      if (!intersection || !intersection.partId) {
 18→        // Clicked empty space - deselect and reset drawing plane
 19→        editorDispatch({ type: 'DESELECT' });
 20→        editorDispatch({ type: 'RESET_DRAWING_PLANE' });
 21→        return;
 22→      }
 23→
 24→      const { partId, objectId, point, faceNormal } = intersection;
 25→
 26→      // Determine face for drawing plane
 27→      if (faceNormal) {
 28→        const faceId = identifyFace(faceNormal);
 29→        const part = project.parts.find((p) => p.id === partId);
 30→        if (part) {
 31→          const plane = faceToDrawingPlane(part, faceId);
 32→          editorDispatch({ type: 'SET_DRAWING_PLANE', plane });
 33→        }
 34→      }
 35→
 36→      if (isEditMode) {
 37→        const part = project.parts.find((p) => p.id === partId && p.assemblyId === activeAssemblyId);
 38→        if (part) {
 39→          editorDispatch({ type: 'SELECT_OBJECT', id: part.id, objectType: 'part' });
 40→          editorDispatch({
 41→            type: 'UPDATE_TOOL_STATE',
 42→            payload: { dragging: true, startPoint: point, dragPartId: part.id },
 43→          });
 44→        } else {
 45→          editorDispatch({ type: 'DESELECT' });
 46→        }
 47→        return;
 48→      }
 49→
 50→      // Normal mode selection hierarchy: part -> assembly -> object
 51→      const part = project.parts.find((p) => p.id === partId);
 52→      if (!part) {
 53→        editorDispatch({ type: 'DESELECT' });
 54→        return;
 55→      }
 56→
 57→      const parametricObject = part.objectId
 58→        ? (project.objects || []).find((o) => o.id === part.objectId && o.editingPolicy === 'parametric')
 59→        : null;
 60→
 61→      if (parametricObject) {
 62→        editorDispatch({ type: 'SELECT_OBJECT', id: part.objectId, objectType: 'object' });
 63→        editorDispatch({
 64→          type: 'UPDATE_TOOL_STATE',
 65→          payload: { dragging: true, startPoint: point, dragObjectId: part.objectId },
 66→        });
 67→      } else if (part.assemblyId) {
 68→        editorDispatch({ type: 'SELECT_OBJECT', id: part.assemblyId, objectType: 'assembly' });
 69→        editorDispatch({
 70→          type: 'UPDATE_TOOL_STATE',
 71→          payload: { dragging: true, startPoint: point, dragAssemblyId: part.assemblyId },
 72→        });
 73→      } else {
 74→        editorDispatch({ type: 'SELECT_OBJECT', id: part.id, objectType: 'part' });
 75→        editorDispatch({
 76→          type: 'UPDATE_TOOL_STATE',
 77→          payload: { dragging: true, startPoint: point, dragPartId: part.id },
 78→        });
 79→      }
 80→    },
 81→
 82→    onPointerMove(intersection, e, toolState, viewport) {
 83→      if (!toolState.dragging || !toolState.startPoint) return;
 84→
 85→      // Get current 3D point on movement plane
 86→      const currentPoint = intersection?.planePoint;
 87→      if (!currentPoint) return;
 88→
 89→      const startPoint = toolState.startPoint;
 90→      let dx = currentPoint.x - startPoint.x;
 91→      let dy = currentPoint.z - startPoint.z; // Three.js Z = domain Y
 92→      let dz = -(currentPoint.y - startPoint.y); // Three.js Y = domain Z (negated for correct direction)
 93→
 94→      // Convert Three.js deltas to domain deltas
 95→      // Three.js: x=domain x, y=domain z, z=domain y
 96→      const domainDelta = {
 97→        dx: dx,
 98→        dy: dy,
 99→        dz: -dz, // correct back
100→      };
101→
102→      if (snapEnabled) {
103→        domainDelta.dx = snapToGrid(domainDelta.dx, SKETCH_GRID_MINOR);
104→        domainDelta.dy = snapToGrid(domainDelta.dy, SKETCH_GRID_MINOR);
105→        domainDelta.dz = snapToGrid(domainDelta.dz, SKETCH_GRID_MINOR);
106→        if (Math.abs(domainDelta.dx) < 1 && Math.abs(domainDelta.dy) < 1 && Math.abs(domainDelta.dz) < 1) return;
107→      }
108→
109→      // For single-part drags, try inference snap on the target position
110→      if (toolState.dragPartId && snapEnabled && inferenceCache) {
111→        const part = project.parts.find((p) => p.id === toolState.dragPartId);
112→        if (part && part.type !== 'dimension') {
113→          const targetPos = {
114→            x: part.position.x + domainDelta.dx,
115→            y: part.position.y + domainDelta.dy,
116→            z: part.position.z + domainDelta.dz,
117→          };
118→
119→          const inferencePoints = inferenceCache.getPoints(project.parts, toolState.dragPartId);
120→          const camera = viewport?.getCamera?.();
121→          const domElement = viewport?.getDomElement?.();
122→
123→          const snapResult = smartSnap3d(targetPos, {
124→            inferencePoints,
125→            gridSize: SKETCH_GRID_MINOR,
126→            camera,
127→            domElement,
128→          });
129→
130→          if (snapResult.inference) {
131→            dispatch({
132→              type: 'PART_UPDATE',
133→              part: { id: toolState.dragPartId, position: snapResult.point },
134→            });
135→
136→            editorDispatch({
137→              type: 'UPDATE_TOOL_STATE',
138→              payload: { startPoint: currentPoint, snapResult },
139→            });
140→            return;
141→          }
142→        }
143→      }
144→
145→      if (toolState.dragObjectId) {
146→        dispatch({
147→          type: 'OBJECT_MOVE',
148→          objectId: toolState.dragObjectId,
149→          delta: domainDelta,
150→        });
151→      } else if (toolState.dragAssemblyId) {
152→        dispatch({
153→          type: 'ASSEMBLY_MOVE',
154→          assemblyId: toolState.dragAssemblyId,
155→          delta: domainDelta,
156→        });
157→      } else if (toolState.dragPartId) {
158→        const part = project.parts.find((p) => p.id === toolState.dragPartId);
159→        if (!part || part.type === 'dimension') return;
160→
161→        const pos = {
162→          x: part.position.x + domainDelta.dx,
163→          y: part.position.y + domainDelta.dy,
164→          z: part.position.z + domainDelta.dz,
165→        };
166→
167→        if (snapEnabled) {
168→          pos.x = snapToGrid(pos.x, SKETCH_GRID_MINOR);
169→          pos.y = snapToGrid(pos.y, SKETCH_GRID_MINOR);
170→          pos.z = snapToGrid(pos.z, SKETCH_GRID_MINOR);
171→        }
172→
173→        dispatch({
174→          type: 'PART_UPDATE',
175→          part: { id: toolState.dragPartId, position: pos },
176→        });
177→      }
178→
179→      editorDispatch({
180→        type: 'UPDATE_TOOL_STATE',
181→        payload: { startPoint: currentPoint, snapResult: null },
182→      });
183→    },
184→
185→    onHover(intersection, e, toolState, viewport) {
186→      if (toolState.dragging) return;
187→
188→      // Detect face under cursor for hover highlight
189→      if (intersection?.partId && intersection?.faceNormal) {
190→        const part = project.parts.find((p) => p.id === intersection.partId);
191→        const faceId = identifyFace(intersection.faceNormal);
192→
193→        if (part) {
194→          editorDispatch({
195→            type: 'UPDATE_TOOL_STATE',
196→            payload: {
197→              hoverPartId: part.id,
198→              hoverFaceId: faceId,
199→            },
200→          });
201→          return;
202→        }
203→      }
204→
205→      // No part hovered
206→      if (toolState.hoverPartId) {
207→        editorDispatch({
208→          type: 'UPDATE_TOOL_STATE',
209→          payload: { hoverPartId: null, hoverFaceId: null },
210→        });
211→      }
212→    },
213→
214→    onPointerUp(intersection, e, toolState) {
215→      if (toolState.dragging) {
216→        editorDispatch({
217→          type: 'UPDATE_TOOL_STATE',
218→          payload: {
219→            dragging: false,
220→            startPoint: null,
221→            dragPartId: null,
222→            dragAssemblyId: null,
223→            dragObjectId: null,
224→            snapResult: null,
225→          },
226→        });
227→      }
228→    },
229→
230→    onDoubleClick(intersection, e, toolState) {
231→      if (isEditMode) return;
232→      if (!intersection?.partId) return;
233→
234→      const part = project.parts.find((p) => p.id === intersection.partId);
235→      if (!part || !part.assemblyId) return;
236→
237→      const parametricObject = part.objectId
238→        ? (project.objects || []).find((o) => o.id === part.objectId && o.editingPolicy === 'parametric')
239→        : null;
240→      if (parametricObject) return;
241→
242→      editorDispatch({ type: 'ENTER_ASSEMBLY_EDIT', assemblyId: part.assemblyId });
243→    },
244→
245→    onKeyDown(e, toolState, currentSelectedId) {
246→      if (e.key === 'Escape' && isEditMode) {
247→        e.preventDefault();
248→        e.stopPropagation();
249→        editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
250→        return;
251→      }
252→
253→      if ((e.key === 'Delete' || e.key === 'Backspace') && currentSelectedId) {
254→        if (selectedType === 'object') {
255→          dispatch({ type: 'OBJECT_DELETE', objectId: currentSelectedId });
256→        } else if (selectedType === 'assembly' && !isEditMode) {
257→          dispatch({ type: 'ASSEMBLY_DELETE_WITH_PARTS', assemblyId: currentSelectedId });
258→        } else {
259→          dispatch({ type: 'PART_DELETE', partId: currentSelectedId });
260→        }
261→        editorDispatch({ type: 'DESELECT' });
262→      }
263→    },
264→
265→    getCursor(toolState) {
266→      if (toolState?.dragging) return 'grabbing';
267→      return 'default';
268→    },
269→  };
270→}
