119→/**
120→ * 3D rectangle drawing handler.
121→ * Click-drag on a host face or the active drawing plane to create a part.
122→ */
123→export function createDrawRectHandler3d({
124→  dispatch,
125→  editorDispatch,
126→  project,
127→  activeAssemblyId,
128→  selectedId,
129→  selectedType,
130→  partType,
131→  snapEnabled,
132→  drawingPlane,
133→  inferenceCache,
134→}) {
135→  function snapLocal(local, plane, viewport) {
136→    if (!snapEnabled) return { local, snapResult: null };
137→
138→    const worldPoint = planeLocalToWorld(local.u, local.v, plane);
139→
140→    const inferencePoints = inferenceCache
141→      ? inferenceCache.getPoints(project.parts)
142→      : null;
143→
144→    const camera = viewport?.getCamera?.();
145→    const domElement = viewport?.getDomElement?.();
146→
147→    const result = smartSnap3d(worldPoint, {
148→      inferencePoints,
149→      gridSize: SKETCH_GRID_MINOR,
150→      plane,
151→      camera,
152→      domElement,
153→    });
154→
155→    if (result.inference) {
156→      return {
157→        local: projectToPlane(result.point, plane),
158→        snapResult: result,
159→      };
160→    }
161→
162→    return {
163→      local: {
164→        u: snapToGrid(local.u, SKETCH_GRID_MINOR),
165→        v: snapToGrid(local.v, SKETCH_GRID_MINOR),
166→      },
167→      snapResult: result,
168→    };
169→  }
170→
171→  function beginDrawing(hostPart, faceId, plane, domainPoint, viewport, toolState) {
172→    const local = projectToPlane(domainPoint, plane);
173→    const { local: snapped, snapResult } = snapLocal(local, plane, viewport);
174→    const placementModuleMode = getDefaultPlacementMode(toolState, activeAssemblyId);
175→
176→    if (plane !== (drawingPlane || GROUND_PLANE)) {
177→      editorDispatch({ type: 'SET_DRAWING_PLANE', plane });
178→    }
179→
180→    editorDispatch({
181→      type: 'UPDATE_TOOL_STATE',
182→      payload: {
183→        drawing: true,
184→        placementPlane: plane,
185→        placementHostPartId: hostPart?.id || null,
186→        placementFaceId: faceId || null,
187→        placementModuleMode,
188→        startLocal: snapped,
189→        currentLocal: snapped,
190→        startWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
191→        currentWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
192→        hoverPartId: hostPart?.id || null,
193→        hoverFaceId: faceId || null,
194→        snapResult,
195→      },
196→    });
197→  }
198→
199→  return {
200→    onPointerDown(intersection, e, toolState, viewport) {
201→      if (e.button !== 0) return;
202→
203→      const hostPart = intersection?.partId
204→        ? project.parts.find((part) => part.id === intersection.partId)
205→        : null;
206→      const faceId = intersection?.faceNormal ? identifyFace(intersection.faceNormal) : null;
207→      const hostObject = hostPart?.objectId
208→        ? project.objects.find((object) => object.id === hostPart.objectId)
209→        : null;
210→
211→      if (hostObject?.editingPolicy === 'parametric') {
212→        editorDispatch({
213→          type: 'SET_STATUS_MESSAGE',
214→          message: 'Detach the object before attaching custom parts to a generated face.',
215→        });
216→        return;
217→      }
218→
219→      const plane = hostPart && faceId
220→        ? faceToDrawingPlane(hostPart, faceId)
221→        : (drawingPlane || GROUND_PLANE);
222→      const domainPoint = hostPart && faceId
223→        ? toDomainPoint(intersection?.point)
224→        : intersection?.drawingPlanePoint;
225→
226→      if (!domainPoint) return;
227→
228→      beginDrawing(hostPart, faceId, plane, domainPoint, viewport, toolState);
229→    },
230→
231→    onPointerMove(intersection, e, toolState, viewport) {
232→      if (!toolState.drawing) return;
233→
234→      const plane = getPlacementPlane(toolState, drawingPlane);
235→      const planePoint = intersection?.drawingPlanePoint;
236→      if (!planePoint) return;
237→
238→      const local = projectToPlane(planePoint, plane);
239→      const { local: snapped, snapResult } = snapLocal(local, plane, viewport);
240→
241→      editorDispatch({
242→        type: 'UPDATE_TOOL_STATE',
243→        payload: {
244→          currentLocal: snapped,
245→          currentWorld: planeLocalToWorld(snapped.u, snapped.v, plane),
246→          snapResult,
247→        },
248→      });
249→    },
250→
251→    onHover(intersection, e, toolState, viewport) {
252→      if (toolState.drawing) return;
253→
254→      if (intersection?.partId && intersection?.faceNormal) {
255→        const part = project.parts.find((entry) => entry.id === intersection.partId);
256→        if (!part) return;
257→
258→        const faceId = identifyFace(intersection.faceNormal);
259→        const plane = faceToDrawingPlane(part, faceId);
260→        const domainPoint = toDomainPoint(intersection.point);
261→        const local = domainPoint ? projectToPlane(domainPoint, plane) : null;
262→        const snapped = local ? snapLocal(local, plane, viewport).snapResult : null;
263→
264→        editorDispatch({
265→          type: 'UPDATE_TOOL_STATE',
266→          payload: {
267→            hoverPartId: part.id,
268→            hoverFaceId: faceId,
269→            snapResult: snapped?.inference ? snapped : null,
270→          },
271→        });
272→        return;
273→      }
274→
275→      clearHover(editorDispatch);
276→    },
277→
278→    onPointerUp(intersection, e, toolState, viewport) {
279→      if (!toolState.drawing || !toolState.startLocal) return;
280→
281→      const plane = getPlacementPlane(toolState, drawingPlane);
282→      let endLocal = toolState.currentLocal;
283→
284→      if (intersection?.drawingPlanePoint) {
285→        const local = projectToPlane(intersection.drawingPlanePoint, plane);
286→        const { local: snapped } = snapLocal(local, plane, viewport);
287→        endLocal = snapped;
288→      }
289→
290→      const uSize = Math.abs(endLocal.u - toolState.startLocal.u);
291→      const vSize = Math.abs(endLocal.v - toolState.startLocal.v);
292→      const minSize = 10;
293→
294→      if (uSize > minSize && vSize > minSize) {
295→        const minU = Math.min(toolState.startLocal.u, endLocal.u);
296→        const minV = Math.min(toolState.startLocal.v, endLocal.v);
297→        const worldPos = planeLocalToWorld(minU, minV, plane);
298→        const hostPart = toolState.placementHostPartId
299→          ? project.parts.find((part) => part.id === toolState.placementHostPartId)
300→          : null;
301→        const faceId = toolState.placementFaceId || plane.sourceFace || null;
302→
303→        const overrides = computeFaceAlignedPartOverrides(
304→          plane,
305→          faceId,
306→          worldPos,
307→          uSize,
308→          vSize,
309→          partType
310→        );
311→
312→        const placementTarget = resolvePlacementTarget({
313→          dispatch,
314→          project,
315→          partType,
316→          hostPart,
317→          activeAssemblyId,
318→          selectedId,
319→          selectedType,
320→          placementModuleMode: getDefaultPlacementMode(toolState, activeAssemblyId),
321→        });
322→
323→        overrides.assemblyId = placementTarget.assemblyId;
324→        overrides.objectId = placementTarget.objectId || hostPart?.objectId || null;
325→
326→        const factory = partFactories[partType];
327→        if (factory) {
328→          const part = factory(overrides);
329→          dispatch({ type: 'PART_ADD', part });
330→
331→          if (placementTarget.assemblyId) {
332→            dispatch({
333→              type: 'ASSEMBLY_ADD_PART',
334→              assemblyId: placementTarget.assemblyId,
335→              partId: part.id,
336→            });
337→          }
338→
339→          if (hostPart && faceId) {
340→            const constraints = buildFaceAttachmentConstraints(part, hostPart, faceId);
341→            for (const definition of constraints) {
342→              dispatch({
343→                type: 'CONSTRAINT_ADD',
344→                constraint: createConstraint(definition),
345→              });
346→            }
347→          }
348→
349→          editorDispatch({
350→            type: 'SET_STATUS_MESSAGE',
351→            message: hostPart
352→              ? `${capitalize(partType)} attached to ${hostPart.name}`
353→              : `${partType}: ${Math.round(uSize)} x ${Math.round(vSize)} mm`,
354→          });
355→        }
356→      }
357→
358→      editorDispatch({
359→        type: 'UPDATE_TOOL_STATE',
360→        payload: {
361→          drawing: false,
362→          placementPlane: null,
363→          placementHostPartId: null,
364→          placementFaceId: null,
365→          startLocal: null,
366→          currentLocal: null,
367→          startWorld: null,
368→          currentWorld: null,
369→          snapResult: null,
370→        },
371→      });
372→    },
373→
374→    onKeyDown(e) {
375→      if (e.key === 'Escape') {
376→        editorDispatch({
377→          type: 'UPDATE_TOOL_STATE',
378→          payload: {
379→            drawing: false,
380→            placementPlane: null,
381→            placementHostPartId: null,
382→            placementFaceId: null,
383→            startLocal: null,
384→            currentLocal: null,
385→            startWorld: null,
386→            currentWorld: null,
387→            hoverPartId: null,
388→            hoverFaceId: null,
389→            snapResult: null,
390→          },
391→        });
392→      }
393→    },
394→
395→    getCursor() {
396→      return 'crosshair';
397→    },
398→  };
399→}
