  1→import { createPanel } from '../../domain/partModels';
  2→import { createConstraint } from '../../domain/constraintModels';
  3→import { computeExtrusionFromFace } from '../../domain/extrusion';
  4→import { identifyFace } from '../../domain/drawingPlane';
  5→import { snapToGrid, smartSnap3d } from '../snap';
  6→import { SKETCH_GRID_MINOR } from '../../domain/defaults';
  7→
  8→/**
  9→ * Push/pull extrusion handler.
 10→ * Click a face and drag outward to create a new part attached to that face.
 11→ * Type a number + Enter for exact distance.
 12→ */
 13→export function createPushPullHandler3d({ dispatch, editorDispatch, project, snapEnabled, inferenceCache }) {
 14→  /**
 15→   * Snap extrusion distance along the extrusion axis using inference points.
 16→   */
 17→  function snapExtrusionDistance(distance, sourcePart, faceId, viewport) {
 18→    if (!snapEnabled) return { distance, snapResult: null };
 19→
 20→    if (!inferenceCache) {
 21→      return { distance: snapToGrid(distance, SKETCH_GRID_MINOR), snapResult: null };
 22→    }
 23→
 24→    // Determine which axis the extrusion operates on
 25→    const axisMap = {
 26→      '+x': 'x', '-x': 'x',
 27→      '+y': 'y', '-y': 'y',
 28→      '+z': 'z', '-z': 'z',
 29→    };
 30→    const axis = axisMap[faceId];
 31→    if (!axis) {
 32→      return { distance: snapToGrid(distance, SKETCH_GRID_MINOR), snapResult: null };
 33→    }
 34→
 35→    // Compute where the extrusion endpoint would be
 36→    const { position } = sourcePart;
 37→    const dims = getSimpleDims(sourcePart);
 38→    let endValue;
 39→    const sign = faceId.startsWith('+') ? 1 : -1;
 40→
 41→    if (sign > 0) {
 42→      endValue = position[axis] + dims[axisToDim(axis)] + distance;
 43→    } else {
 44→      endValue = position[axis] - distance;
 45→    }
 46→
 47→    // Check if any inference point's axis value is close to endValue
 48→    const inferencePoints = inferenceCache.getPoints(project.parts, sourcePart.id);
 49→    const camera = viewport?.getCamera?.();
 50→    const domElement = viewport?.getDomElement?.();
 51→
 52→    // Use smartSnap3d with a synthetic point along the extrusion axis
 53→    const probePoint = { ...position };
 54→    probePoint[axis] = endValue;
 55→
 56→    const snapResult = smartSnap3d(probePoint, {
 57→      inferencePoints,
 58→      gridSize: SKETCH_GRID_MINOR,
 59→      camera,
 60→      domElement,
 61→    });
 62→
 63→    if (snapResult.inference) {
 64→      // Compute the snapped distance from the inference point's axis value
 65→      let snappedEnd = snapResult.inference[axis];
 66→      let snappedDistance;
 67→      if (sign > 0) {
 68→        snappedDistance = snappedEnd - position[axis] - dims[axisToDim(axis)];
 69→      } else {
 70→        snappedDistance = position[axis] - snappedEnd;
 71→      }
 72→      return { distance: snappedDistance, snapResult };
 73→    }
 74→
 75→    return { distance: snapToGrid(distance, SKETCH_GRID_MINOR), snapResult: null };
 76→  }
 77→
 78→  return {
 79→    onPointerDown(intersection, e, toolState, viewport) {
 80→      if (e.button !== 0) return;
 81→
 82→      if (!intersection || !intersection.partId || !intersection.faceNormal) {
 83→        editorDispatch({
 84→          type: 'UPDATE_TOOL_STATE',
 85→          payload: { extruding: false, sourcePart: null, faceId: null, numericInput: '', snapResult: null },
 86→        });
 87→        return;
 88→      }
 89→
 90→      const part = project.parts.find((p) => p.id === intersection.partId);
 91→      if (!part) return;
 92→
 93→      const faceId = identifyFace(intersection.faceNormal);
 94→
 95→      editorDispatch({
 96→        type: 'UPDATE_TOOL_STATE',
 97→        payload: {
 98→          extruding: true,
 99→          sourcePart: part,
100→          faceId,
101→          startPoint: intersection.point,
102→          faceNormal: intersection.faceNormal,
103→          extrusionDistance: 0,
104→          numericInput: '',
105→          snapResult: null,
106→        },
107→      });
108→    },
109→
110→    onPointerMove(intersection, e, toolState, viewport) {
111→      if (!toolState.extruding || !toolState.startPoint || !toolState.faceNormal) return;
112→
113→      const currentPoint = intersection?.planePoint;
114→      if (!currentPoint) return;
115→
116→      // Project mouse movement onto face normal axis
117→      const fn = toolState.faceNormal;
118→      const dx = currentPoint.x - toolState.startPoint.x;
119→      const dy = currentPoint.y - toolState.startPoint.y;
120→      const dz = currentPoint.z - toolState.startPoint.z;
121→
122→      // Dot product with face normal gives distance along normal
123→      let distance = dx * fn.x + dy * fn.y + dz * fn.z;
124→
125→      const { distance: snappedDistance, snapResult } = snapExtrusionDistance(
126→        distance, toolState.sourcePart, toolState.faceId, viewport
127→      );
128→
129→      editorDispatch({
130→        type: 'UPDATE_TOOL_STATE',
131→        payload: { extrusionDistance: snappedDistance, snapResult },
132→      });
133→    },
134→
135→    onHover(intersection, e, toolState, viewport) {
136→      if (toolState.extruding) return;
137→
138→      // Highlight face under cursor
139→      if (intersection?.partId && intersection?.faceNormal) {
140→        const part = project.parts.find((p) => p.id === intersection.partId);
141→        const faceId = identifyFace(intersection.faceNormal);
142→
143→        if (part) {
144→          editorDispatch({
145→            type: 'UPDATE_TOOL_STATE',
146→            payload: { hoverPartId: part.id, hoverFaceId: faceId },
147→          });
148→          return;
149→        }
150→      }
151→
152→      if (toolState.hoverPartId) {
153→        editorDispatch({
154→          type: 'UPDATE_TOOL_STATE',
155→          payload: { hoverPartId: null, hoverFaceId: null },
156→        });
157→      }
158→    },
159→
160→    onPointerUp(intersection, e, toolState, viewport) {
161→      if (!toolState.extruding || !toolState.sourcePart || !toolState.faceId) return;
162→
163→      const distance = toolState.extrusionDistance || 0;
164→      if (Math.abs(distance) < 1) {
165→        // Too small - keep state for numeric input
166→        return;
167→      }
168→
169→      commitExtrusion(dispatch, editorDispatch, toolState.sourcePart, toolState.faceId, distance);
170→    },
171→
172→    onKeyDown(e, toolState) {
173→      if (!toolState.extruding && !toolState.sourcePart) return;
174→
175→      // Numeric input mode
176→      if (e.key >= '0' && e.key <= '9') {
177→        e.preventDefault();
178→        editorDispatch({
179→          type: 'UPDATE_TOOL_STATE',
180→          payload: { numericInput: (toolState.numericInput || '') + e.key },
181→        });
182→        return;
183→      }
184→
185→      if (e.key === '.' && !(toolState.numericInput || '').includes('.')) {
186→        e.preventDefault();
187→        editorDispatch({
188→          type: 'UPDATE_TOOL_STATE',
189→          payload: { numericInput: (toolState.numericInput || '') + '.' },
190→        });
191→        return;
192→      }
193→
194→      if (e.key === 'Backspace' && toolState.numericInput) {
195→        e.preventDefault();
196→        editorDispatch({
197→          type: 'UPDATE_TOOL_STATE',
198→          payload: { numericInput: toolState.numericInput.slice(0, -1) },
199→        });
200→        return;
201→      }
202→
203→      if (e.key === '-' && !(toolState.numericInput || '').includes('-')) {
204→        e.preventDefault();
205→        editorDispatch({
206→          type: 'UPDATE_TOOL_STATE',
207→          payload: { numericInput: '-' + (toolState.numericInput || '') },
208→        });
209→        return;
210→      }
211→
212→      if (e.key === 'Enter' && toolState.numericInput && toolState.sourcePart && toolState.faceId) {
213→        e.preventDefault();
214→        const distance = parseFloat(toolState.numericInput);
215→        if (!isNaN(distance) && Math.abs(distance) >= 1) {
216→          commitExtrusion(dispatch, editorDispatch, toolState.sourcePart, toolState.faceId, distance);
217→        }
218→        return;
219→      }
220→
221→      if (e.key === 'Escape') {
222→        editorDispatch({
223→          type: 'UPDATE_TOOL_STATE',
224→          payload: {
225→            extruding: false,
226→            sourcePart: null,
227→            faceId: null,
228→            startPoint: null,
229→            faceNormal: null,
230→            extrusionDistance: 0,
231→            numericInput: '',
232→            snapResult: null,
233→          },
234→        });
235→      }
236→    },
237→
238→    getCursor(toolState) {
239→      if (toolState?.extruding) return 'ns-resize';
240→      return 'crosshair';
241→    },
