  1→import {
  2→  findNearestInference,
  3→  findNearestInferenceOnPlane,
  4→  computeWorldThreshold,
  5→} from './inferenceEngine';
  6→
  7→export function snapToGrid(value, gridSize) {
  8→  return Math.round(value / gridSize) * gridSize;
  9→}
 10→
 11→export function snapPoint(point, gridSize) {
 12→  return {
 13→    x: snapToGrid(point.x, gridSize),
 14→    y: snapToGrid(point.y, gridSize),
 15→  };
 16→}
 17→
 18→/**
 19→ * Snap a 3D point to the nearest grid intersection on a given plane.
 20→ * Projects to plane local coords, snaps, then converts back.
 21→ */
 22→export function snapPoint3d(point, gridSize, plane) {
 23→  if (!plane) {
 24→    return {
 25→      x: snapToGrid(point.x, gridSize),
 26→      y: snapToGrid(point.y, gridSize),
 27→      z: snapToGrid(point.z, gridSize),
 28→    };
 29→  }
 30→
 31→  // Project point onto plane local coords
 32→  const dx = point.x - plane.origin.x;
 33→  const dy = point.y - plane.origin.y;
 34→  const dz = point.z - plane.origin.z;
 35→  const u = dx * plane.uAxis.x + dy * plane.uAxis.y + dz * plane.uAxis.z;
 36→  const v = dx * plane.vAxis.x + dy * plane.vAxis.y + dz * plane.vAxis.z;
 37→
 38→  // Snap in local coords
 39→  const su = snapToGrid(u, gridSize);
 40→  const sv = snapToGrid(v, gridSize);
 41→
 42→  // Convert back to world
 43→  return {
 44→    x: plane.origin.x + su * plane.uAxis.x + sv * plane.vAxis.x,
 45→    y: plane.origin.y + su * plane.uAxis.y + sv * plane.vAxis.y,
 46→    z: plane.origin.z + su * plane.uAxis.z + sv * plane.vAxis.z,
 47→  };
 48→}
 49→
 50→/**
 51→ * Smart 3D snap — inference-first, then grid fallback.
 52→ *
 53→ * @param {{x: number, y: number, z: number}} point - Raw cursor position in domain coords
 54→ * @param {Object} options
 55→ * @param {Array} [options.inferencePoints] - Pre-collected inference points
 56→ * @param {number} [options.gridSize] - Grid snap size in mm (default 50)
 57→ * @param {Object} [options.plane] - Drawing plane (for on-plane inference)
 58→ * @param {Object} [options.camera] - Three.js camera (for screen-space threshold)
 59→ * @param {Object} [options.domElement] - Renderer DOM element
 60→ * @param {number} [options.screenPx] - Screen-space threshold in px (default 15)
 61→ * @returns {import('./inferenceEngine').SnapResult}
 62→ */
 63→export function smartSnap3d(point, options = {}) {
 64→  const {
 65→    inferencePoints,
 66→    gridSize = 50,
 67→    plane,
 68→    camera,
 69→    domElement,
 70→    screenPx = 15,
 71→  } = options;
 72→
 73→  // Try inference snap first
 74→  if (inferencePoints && inferencePoints.length > 0) {
 75→    const thresholdMm = (camera && domElement)
 76→      ? computeWorldThreshold(camera, domElement, screenPx, point)
 77→      : gridSize; // fallback: use grid size as threshold
 78→
 79→    const inferenceResult = plane
 80→      ? findNearestInferenceOnPlane(point, inferencePoints, plane, thresholdMm)
 81→      : findNearestInference(point, inferencePoints, thresholdMm);
 82→
 83→    if (inferenceResult) {
 84→      return inferenceResult;
 85→    }
 86→  }
 87→
 88→  // Fall back to grid snap
 89→  const gridSnapped = plane
 90→    ? snapPoint3d(point, gridSize, plane)
 91→    : {
 92→        x: snapToGrid(point.x, gridSize),
 93→        y: snapToGrid(point.y, gridSize),
 94→        z: snapToGrid(point.z, gridSize),
 95→      };
 96→
 97→  return {
 98→    point: gridSnapped,
 99→    inference: null,
100→    snapped: true,
101→  };
102→}
