198→    const rect = renderer.domElement.getBoundingClientRect();
199→    if (!rect.width || !rect.height) return;
200→
201→    const pointer = new THREE.Vector2(
202→      ((clientX - rect.left) / rect.width) * 2 - 1,
203→      -(((clientY - rect.top) / rect.height) * 2 - 1)
204→    );
205→
206→    raycaster.setFromCamera(pointer, camera);
207→    const hits = raycaster.intersectObject(worldRoot, true);
208→    const seenTargets = new Set();
209→    const targets = [];
210→
211→    for (const hit of hits) {
212→      const target = resolvePickTarget(hit.object);
213→      if (!target) continue;
214→
215→      const key = `${target.floorId || ''}:${target.kind}:${target.sourceId}`;
216→      if (seenTargets.has(key)) continue;
217→      seenTargets.add(key);
218→      targets.push(target);
219→    }
220→
221→    if (!targets.length) {
222→      pickHandler(null);
223→      return;
224→    }
225→
226→    const preferredTarget = pickContext.activeFloorId
227→      ? targets.find((target) => target.floorId === pickContext.activeFloorId) || null
228→      : null;
229→
230→    pickHandler(preferredTarget || targets[0]);
231→  };
232→
233→  const handlePointerDown = (event) => {
234→    if (navigationMode !== 'inspect') {
235→      pointerDown = null;
236→      return;
237→    }
238→
239→    if (navigationModifierActive) {
240→      pointerDown = null;
241→      return;
242→    }
243→
244→    if (event.button !== 0) {
245→      pointerDown = null;
246→      return;
247→    }
248→
249→    pointerDown = {
250→      x: event.clientX,
251→      y: event.clientY,
252→    };
253→  };
254→
255→  const handlePointerCancel = () => {
256→    pointerDown = null;
257→  };
258→
259→  const handlePointerUp = (event) => {
260→    if (navigationMode !== 'inspect') {
261→      pointerDown = null;
262→      return;
263→    }
264→
265→    if (navigationModifierActive) {
266→      pointerDown = null;
267→      return;
268→    }
269→
270→    if (event.button !== 0 || !pointerDown) {
271→      pointerDown = null;
272→      return;
273→    }
274→
275→    const dx = event.clientX - pointerDown.x;
276→    const dy = event.clientY - pointerDown.y;
277→    pointerDown = null;
278→
279→    if (Math.hypot(dx, dy) > CLICK_DISTANCE_THRESHOLD) {
280→      return;
281→    }
282→
283→    pickObjectAt(event.clientX, event.clientY);
284→  };
285→
286→  renderer.domElement.addEventListener('pointerdown', handlePointerDown);
287→  renderer.domElement.addEventListener('pointerup', handlePointerUp);
288→  renderer.domElement.addEventListener('pointercancel', handlePointerCancel);
289→  renderer.domElement.addEventListener('pointerleave', handlePointerCancel);
290→
291→  animationFrame = window.requestAnimationFrame(renderFrame);
292→
293→  return {
294→    setWorld(nextRoot, bounds, groundLevel = 0) {
295→      const hadWorld = !!worldRoot;
296→      const walkPose = navigationMode === 'walk' ? walkNavigation.capturePose() : null;
297→
298→      if (worldRoot) {
299→        scene.remove(worldRoot);
300→        disposeScene(worldRoot, { disposeMaterials: true });
301→      }
302→
303→      if (gridHelper) {
304→        scene.remove(gridHelper);
305→        gridHelper.geometry?.dispose?.();
306→        gridHelper.material?.dispose?.();
307→      }
308→
309→      worldRoot = nextRoot;
310→      currentBounds = descriptorBoundsToWorldBox(bounds);
311→      inspectNavigation.setBounds(currentBounds);
312→      gridHelper = createGrid(bounds, groundLevel);
313→      scene.add(gridHelper);
314→      scene.add(worldRoot);
315→      if (!hadWorld && navigationMode === 'inspect') {
316→        inspectNavigation.resetView();
317→      }
318→
319→      if (walkPose) {
320→        walkNavigation.restorePose(walkPose);
321→      }
322→    },
323→    resetView() {
324→      if (navigationMode === 'walk') {
325→        if (activeFloorContext.floorId) {
326→          walkPoseByFloorId.delete(activeFloorContext.floorId);
327→        }
328→        restoreWalkPose({ forceSpawn: true });
329→        return;
330→      }
331→      inspectNavigation.resetView();
332→    },
333→    fit() {
334→      inspectNavigation.resetView();
335→    },
336→    setProjectionPreset(presetName) {
337→      inspectNavigation.setProjectionPreset(presetName);
338→    },
339→    setInspectLeftButtonRotateEnabled(enabled) {
340→      inspectNavigation.setLeftButtonRotateEnabled(enabled);
341→    },
342→    setNavigationModifierActive(active) {
343→      navigationModifierActive = !!active;
344→      if (navigationModifierActive) {
345→        pointerDown = null;
346→      }
347→    },
348→    setPickHandler(handler) {
349→      pickHandler = typeof handler === 'function' ? handler : null;
350→    },
351→    setPickContext(nextContext = {}) {
352→      pickContext = {
353→        ...pickContext,
354→        ...nextContext,
355→      };
356→    },
357→    setNavigationMode,
358→    setActiveFloorContext(nextContext = {}) {
359→      const previousFloorId = activeFloorContext.floorId;
360→      const nextFloorId = nextContext.floorId ?? activeFloorContext.floorId;
361→      const floorChanged = previousFloorId !== nextFloorId;
362→
363→      if (navigationMode === 'walk' && floorChanged && previousFloorId) {
364→        saveCurrentWalkPose();
365→      }
366→
367→      activeFloorContext = {
368→        ...activeFloorContext,
369→        ...nextContext,
370→      };
371→
372→      if (navigationMode === 'walk' && floorChanged) {
373→        restoreWalkPose();
374→      }
375→    },
376→    setWalkUiHandler(handler) {
377→      walkUiHandler = typeof handler === 'function' ? handler : null;
378→      emitWalkUiState();
379→    },
380→    setWalkExitHandler(handler) {
381→      walkExitHandler = typeof handler === 'function' ? handler : null;
382→    },
383→    setCompassHeadingHandler(handler) {
384→      compassHeadingHandler = typeof handler === 'function' ? handler : null;
385→      emitCompassHeading();
386→    },
387→    resize,
388→    dispose() {
389→      window.cancelAnimationFrame(animationFrame);
390→      inspectNavigation.dispose();
391→      walkNavigation.dispose();
392→      renderer.domElement.removeEventListener('pointerdown', handlePointerDown);
393→      renderer.domElement.removeEventListener('pointerup', handlePointerUp);
394→      renderer.domElement.removeEventListener('pointercancel', handlePointerCancel);
395→      renderer.domElement.removeEventListener('pointerleave', handlePointerCancel);
396→
397→      if (worldRoot) {
398→        scene.remove(worldRoot);
399→        disposeScene(worldRoot, { disposeMaterials: true });
400→      }
401→
402→      if (gridHelper) {
403→        scene.remove(gridHelper);
404→        gridHelper.geometry?.dispose?.();
405→        gridHelper.material?.dispose?.();
406→      }
407→
408→      disposeMaterialPalette(materialPalette);
409→      timer.dispose();
410→      renderer.dispose();
411→      renderer.domElement.remove();
412→    },
413→    materialPalette,
414→    getCamera() {
415→      return camera;
416→    },
417→    getDomElement() {
418→      return renderer.domElement;
419→    },
420→    getScene() {
421→      return scene;
422→    },
423→    getRaycaster() {
424→      return raycaster;
425→    },
426→  };
427→}
