  1→import * as THREE from 'three';
  2→import { getSolidPlane } from '../domain/solidGeometry';
  3→
  4→const WOOD_COLOR = 0xD2B48C;
  5→const SELECTED_TINT = 0xB8860B;
  6→const EDGE_COLOR = 0x333333;
  7→
  8→/**
  9→ * Face index mapping for BoxGeometry.
 10→ * Three.js BoxGeometry has 6 groups (2 triangles each):
 11→ * group 0: +x, group 1: -x, group 2: +y, group 3: -y, group 4: +z, group 5: -z
 12→ */
 13→const BOX_FACE_IDS = ['+x', '-x', '+y', '-y', '+z', '-z'];
 14→
 15→function createBoxMesh(width, height, depth, color) {
 16→  const geometry = new THREE.BoxGeometry(width, height, depth);
 17→  const material = new THREE.MeshStandardMaterial({
 18→    color,
 19→    roughness: 0.7,
 20→    metalness: 0.05,
 21→  });
 22→  const mesh = new THREE.Mesh(geometry, material);
 23→  mesh.userData.faceIds = BOX_FACE_IDS;
 24→  return mesh;
 25→}
 26→
 27→function createCylinderMesh(diameter, height, color) {
 28→  const geometry = new THREE.CylinderGeometry(diameter / 2, diameter / 2, height, 16);
 29→  const material = new THREE.MeshStandardMaterial({
 30→    color,
 31→    roughness: 0.7,
 32→    metalness: 0.05,
 33→  });
 34→  return new THREE.Mesh(geometry, material);
 35→}
 36→
 37→function addEdges(mesh) {
 38→  const edges = new THREE.EdgesGeometry(mesh.geometry);
 39→  const line = new THREE.LineSegments(
 40→    edges,
 41→    new THREE.LineBasicMaterial({ color: EDGE_COLOR, transparent: true, opacity: 0.3 })
 42→  );
 43→  mesh.add(line);
 44→}
 45→
 46→function domainPointToThree(point) {
 47→  return new THREE.Vector3(point.x, point.z, point.y);
 48→}
 49→
 50→function domainVectorToThree(vector) {
 51→  return new THREE.Vector3(vector.x, vector.z, vector.y);
 52→}
 53→
 54→function createPanelMesh(part, isSelected) {
 55→  const color = isSelected ? SELECTED_TINT : WOOD_COLOR;
 56→  const mesh = createBoxMesh(part.width, part.thickness, part.depth, color);
 57→  // Three.js: x = part.x + w/2, y = part.z + h/2, z = part.y + d/2
 58→  mesh.position.set(
 59→    part.position.x + part.width / 2,
 60→    part.position.z + part.thickness / 2,
 61→    part.position.y + part.depth / 2
 62→  );
 63→  addEdges(mesh);
 64→  return mesh;
 65→}
 66→
 67→function createLegMesh(part, isSelected) {
 68→  const color = isSelected ? SELECTED_TINT : 0x8B7355;
 69→
 70→  if (part.profile === 'round') {
 71→    const mesh = createCylinderMesh(part.width, part.height, color);
 72→    mesh.position.set(
 73→      part.position.x + part.width / 2,
 74→      part.position.z + part.height / 2,
 75→      part.position.y + part.depth / 2
 76→    );
 77→    addEdges(mesh);
 78→    return mesh;
 79→  }
 80→
 81→  const mesh = createBoxMesh(part.width, part.height, part.depth, color);
 82→  mesh.position.set(
 83→    part.position.x + part.width / 2,
 84→    part.position.z + part.height / 2,
 85→    part.position.y + part.depth / 2
 86→  );
 87→  addEdges(mesh);
 88→  return mesh;
 89→}
 90→
 91→function createFrameMesh(part, isSelected) {
 92→  const color = isSelected ? SELECTED_TINT : 0xA0522D;
 93→  let w, h, d;
 94→
 95→  if (part.axis === 'y') {
 96→    w = part.width;
 97→    h = part.height;
 98→    d = part.length;
 99→  } else {
100→    w = part.length;
101→    h = part.height;
102→    d = part.width;
103→  }
104→
105→  const mesh = createBoxMesh(w, h, d, color);
106→  mesh.position.set(
107→    part.position.x + w / 2,
108→    part.position.z + h / 2,
109→    part.position.y + d / 2
110→  );
111→  addEdges(mesh);
112→  return mesh;
113→}
114→
115→function createSolidMesh(part, isSelected) {
116→  const color = isSelected ? SELECTED_TINT : 0xC6A46A;
117→  const shape = new THREE.Shape();
118→  const points = part.profilePoints || [];
119→  if (points.length < 3) return null;
120→
121→  shape.moveTo(points[0].u, points[0].v);
122→  for (let index = 1; index < points.length; index += 1) {
123→    shape.lineTo(points[index].u, points[index].v);
124→  }
125→  shape.closePath();
126→
127→  const geometry = new THREE.ExtrudeGeometry(shape, {
128→    depth: Math.max(1, part.extrusionDepth || 120),
129→    bevelEnabled: false,
130→    steps: 1,
131→  });
132→  const material = new THREE.MeshStandardMaterial({
133→    color,
134→    roughness: 0.7,
135→    metalness: 0.05,
136→    side: THREE.DoubleSide,
137→  });
138→  const mesh = new THREE.Mesh(geometry, material);
139→
140→  const plane = getSolidPlane(part);
141→  const origin = domainPointToThree(plane.origin);
142→  const uAxis = domainVectorToThree(plane.uAxis);
143→  const vAxis = domainVectorToThree(plane.vAxis);
144→  const normal = domainVectorToThree(plane.normal);
145→  const basis = new THREE.Matrix4().makeBasis(uAxis, vAxis, normal);
146→  basis.setPosition(origin);
147→  mesh.applyMatrix4(basis);
148→  addEdges(mesh);
149→  return mesh;
150→}
151→
152→function isPartSelected(part, selection) {
153→  if (!selection) return false;
154→  if (selection.selectedType === 'object') return part.objectId === selection.selectedId;
155→  if (selection.selectedType === 'assembly') return part.assemblyId === selection.selectedId;
156→  return part.id === selection.selectedId;
157→}
158→
159→export function buildSketchPreviewRoot(parts, selection) {
160→  const root = new THREE.Group();
161→
162→  for (const part of parts) {
163→    // Skip dimension, cutout, hole in 3D for V1
164→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
165→
166→    const isSelected = isPartSelected(part, selection);
167→    let mesh;
168→
169→    switch (part.type) {
170→      case 'panel':
171→        mesh = createPanelMesh(part, isSelected);
172→        break;
173→      case 'leg':
174→        mesh = createLegMesh(part, isSelected);
175→        break;
176→      case 'frame':
177→        mesh = createFrameMesh(part, isSelected);
178→        break;
179→      case 'solid':
180→        mesh = createSolidMesh(part, isSelected);
181→        break;
182→      default:
183→        continue;
184→    }
185→
186→    if (mesh) {
187→      mesh.userData.previewTarget = { sourceId: part.id, kind: 'part' };
188→      root.add(mesh);
189→    }
190→  }
191→
192→  return root;
193→}
