  1→/**
  2→ * Inference engine — pure-function snap system for 3D sketch tools.
  3→ * Works entirely in domain coordinates (x=width, y=depth, z=height).
  4→ * No Three.js dependency.
  5→ */
  6→
  7→import { getPartCorners, getPartEdgeMidpoints, getPartFaceCenters } from '../domain/partGeometry';
  8→
  9→/**
 10→ * @typedef {Object} InferencePoint
 11→ * @property {number} x
 12→ * @property {number} y
 13→ * @property {number} z
 14→ * @property {'corner'|'midpoint'|'faceCenter'} type
 15→ * @property {string} partId
 16→ * @property {string} [faceId] - Only set for faceCenter type
 17→ */
 18→
 19→/**
 20→ * @typedef {Object} SnapResult
 21→ * @property {{x: number, y: number, z: number}} point
 22→ * @property {InferencePoint|null} inference - The matched inference point, or null if grid-snapped
 23→ * @property {boolean} snapped - Whether snap was applied (inference or grid)
 24→ */
 25→
 26→/**
 27→ * Collect all inference points from a set of parts.
 28→ * @param {Array} parts - Array of part objects
 29→ * @param {Object} [options]
 30→ * @param {string} [options.excludePartId] - Part to exclude (e.g., the one being dragged)
 31→ * @returns {InferencePoint[]}
 32→ */
 33→export function collectInferencePoints(parts, options = {}) {
 34→  const { excludePartId } = options;
 35→  const points = [];
 36→
 37→  for (const part of parts) {
 38→    if (part.id === excludePartId) continue;
 39→    if (part.type === 'dimension' || part.type === 'cutout' || part.type === 'hole') continue;
 40→
 41→    const partId = part.id;
 42→
 43→    // Corners (8)
 44→    for (const c of getPartCorners(part)) {
 45→      points.push({ x: c.x, y: c.y, z: c.z, type: 'corner', partId });
 46→    }
 47→
 48→    // Edge midpoints (12)
 49→    for (const m of getPartEdgeMidpoints(part)) {
 50→      points.push({ x: m.x, y: m.y, z: m.z, type: 'midpoint', partId });
 51→    }
 52→
 53→    // Face centers (6)
 54→    for (const fc of getPartFaceCenters(part)) {
 55→      points.push({ x: fc.x, y: fc.y, z: fc.z, type: 'faceCenter', partId, faceId: fc.faceId });
 56→    }
 57→  }
 58→
 59→  return points;
 60→}
 61→
 62→/**
 63→ * Find the nearest inference point to a cursor position within a threshold.
 64→ * Uses priority: corner > midpoint > faceCenter.
 65→ * @param {{x: number, y: number, z: number}} cursor - Cursor position in domain coords
 66→ * @param {InferencePoint[]} points - Candidate inference points
 67→ * @param {number} thresholdMm - Maximum distance in mm
 68→ * @returns {SnapResult|null} - Best match or null if none within threshold
 69→ */
 70→export function findNearestInference(cursor, points, thresholdMm) {
 71→  if (!points.length) return null;
 72→
 73→  const typePriority = { corner: 0, midpoint: 1, faceCenter: 2 };
 74→  let best = null;
 75→  let bestDist = thresholdMm;
 76→  let bestPriority = 3;
 77→
 78→  for (const p of points) {
 79→    const dx = cursor.x - p.x;
 80→    const dy = cursor.y - p.y;
 81→    const dz = cursor.z - p.z;
 82→    const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
 83→    const priority = typePriority[p.type] ?? 3;
 84→
 85→    if (dist < bestDist || (dist === bestDist && priority < bestPriority)) {
 86→      best = p;
 87→      bestDist = dist;
 88→      bestPriority = priority;
 89→    }
 90→  }
 91→
 92→  if (!best) return null;
 93→
 94→  return {
 95→    point: { x: best.x, y: best.y, z: best.z },
 96→    inference: best,
 97→    snapped: true,
 98→  };
 99→}
100→
101→/**
102→ * Find the nearest inference point projected onto a drawing plane.
103→ * Only considers the 2D distance on the plane (ignoring normal component).
104→ * @param {{x: number, y: number, z: number}} cursor - Cursor position in domain coords
105→ * @param {InferencePoint[]} points - Candidate inference points
106→ * @param {Object} plane - Drawing plane with origin, uAxis, vAxis, normal
107→ * @param {number} thresholdMm - Maximum distance in mm (on plane)
108→ * @returns {SnapResult|null}
109→ */
110→export function findNearestInferenceOnPlane(cursor, points, plane, thresholdMm) {
111→  if (!points.length || !plane) return findNearestInference(cursor, points, thresholdMm);
112→
113→  // Project cursor to plane
114→  const cursorU = projectOnAxis(cursor, plane.origin, plane.uAxis);
115→  const cursorV = projectOnAxis(cursor, plane.origin, plane.vAxis);
116→  const cursorN = projectOnAxis(cursor, plane.origin, plane.normal);
117→
118→  const typePriority = { corner: 0, midpoint: 1, faceCenter: 2 };
119→  let best = null;
120→  let bestDist = thresholdMm;
121→  let bestPriority = 3;
122→
123→  for (const p of points) {
124→    const pu = projectOnAxis(p, plane.origin, plane.uAxis);
125→    const pv = projectOnAxis(p, plane.origin, plane.vAxis);
126→    const pn = projectOnAxis(p, plane.origin, plane.normal);
127→
128→    // Only consider points near the plane (within a tolerance)
129→    if (Math.abs(pn - cursorN) > thresholdMm) continue;
130→
131→    const du = cursorU - pu;
132→    const dv = cursorV - pv;
133→    const dist = Math.sqrt(du * du + dv * dv);
134→    const priority = typePriority[p.type] ?? 3;
135→
136→    if (dist < bestDist || (dist === bestDist && priority < bestPriority)) {
137→      best = p;
138→      bestDist = dist;
139→      bestPriority = priority;
140→    }
141→  }
142→
143→  if (!best) return null;
144→
145→  return {
146→    point: { x: best.x, y: best.y, z: best.z },
147→    inference: best,
148→    snapped: true,
149→  };
150→}
151→
152→/**
153→ * Find alignment axes — cases where the cursor is nearly aligned with
154→ * inference points along a single axis.
155→ * @param {{x: number, y: number, z: number}} cursor
156→ * @param {InferencePoint[]} points
157→ * @param {number} thresholdMm
158→ * @returns {Array<{axis: 'x'|'y'|'z', value: number, points: InferencePoint[]}>}
159→ */
160→export function findAlignmentAxes(cursor, points, thresholdMm) {
161→  const axes = ['x', 'y', 'z'];
162→  const result = [];
163→
164→  for (const axis of axes) {
165→    const aligned = [];
166→    for (const p of points) {
167→      if (Math.abs(cursor[axis] - p[axis]) < thresholdMm) {
168→        aligned.push(p);
169→      }
170→    }
171→    if (aligned.length > 0) {
172→      result.push({ axis, value: cursor[axis], points: aligned });
173→    }
174→  }
175→
176→  return result;
177→}
178→
179→/**
180→ * Compute the world-space threshold in mm that corresponds to a given
181→ * screen-space pixel distance at a reference point.
182→ * @param {Object} camera - Three.js camera (PerspectiveCamera or OrthographicCamera)
183→ * @param {Object} domElement - Renderer DOM element
184→ * @param {number} screenPx - Screen-space threshold in pixels (e.g., 15)
185→ * @param {{x: number, y: number, z: number}} refPoint - Reference point in domain coords
186→ * @returns {number} Threshold in mm
187→ */
188→export function computeWorldThreshold(camera, domElement, screenPx, refPoint) {
189→  if (!camera || !domElement) return 50; // fallback
190→
191→  const width = domElement.clientWidth || domElement.offsetWidth || 1;
192→
193→  if (camera.isOrthographicCamera) {
194→    // For ortho: pixels / (width / (right - left)) gives world units per pixel
195→    const worldPerPx = (camera.right - camera.left) / width;
196→    return screenPx * worldPerPx;
197→  }
198→
199→  // For perspective: use distance from camera to reference point
200→  // Domain coords to Three.js: x=x, y=z, z=y
201→  const camPos = camera.position;
202→  const dx = refPoint.x - camPos.x;
203→  const dy = refPoint.z - camPos.y; // domain z -> three y
204→  const dz = refPoint.y - camPos.z; // domain y -> three z
205→  const dist = Math.sqrt(dx * dx + dy * dy + dz * dz);
206→
207→  // At distance d, visible width = 2 * d * tan(fov/2)
208→  const fovRad = (camera.fov * Math.PI) / 180;
209→  const visibleWidth = 2 * dist * Math.tan(fovRad / 2);
210→  const worldPerPx = visibleWidth / width;
211→
212→  return screenPx * worldPerPx;
213→}
214→
215→// --- Helpers ---
216→
217→function projectOnAxis(point, origin, axis) {
218→  const dx = point.x - origin.x;
219→  const dy = point.y - origin.y;
220→  const dz = point.z - origin.z;
221→  return dx * axis.x + dy * axis.y + dz * axis.z;
222→}
