102→
103→    case 'TOGGLE_GRID':
104→      return { ...state, showGrid: !state.showGrid };
105→
106→    case 'TOGGLE_SNAP':
107→      return { ...state, snapEnabled: !state.snapEnabled };
108→
109→    case 'SET_STATUS_MESSAGE':
