  1→/**
  2→ * Centralized part geometry extraction — pure functions, no React/Three.js deps.
  3→ * Replaces duplicated getPartDimensions in drawingPlane.js and extrusion.js.
  4→ */
  5→
  6→import { getSolidBounds, getSolidEdgeMidpoints, getSolidFaceCenters, getSolidVertices } from './solidGeometry';
  7→
  8→/**
  9→ * Get uniform dimensions for any part type.
 10→ * @param {Object} part
 11→ * @returns {{ width: number, depth: number, height: number }}
 12→ */
 13→export function getPartDimensions(part) {
 14→  switch (part.type) {
 15→    case 'panel':
 16→      return { width: part.width, depth: part.depth, height: part.thickness };
 17→    case 'leg':
 18→      return { width: part.width, depth: part.depth, height: part.height };
 19→    case 'frame': {
 20→      const w = part.axis === 'y' ? part.width : part.length;
 21→      const d = part.axis === 'y' ? part.length : part.width;
 22→      return { width: w, depth: d, height: part.height };
 23→    }
 24→    case 'solid': {
 25→      const bounds = getSolidBounds(part);
 26→      return {
 27→        width: bounds.max.x - bounds.min.x,
 28→        depth: bounds.max.y - bounds.min.y,
 29→        height: bounds.max.z - bounds.min.z,
 30→      };
 31→    }
 32→    default:
 33→      return { width: part.width || 100, depth: part.depth || 100, height: part.height || part.thickness || 18 };
 34→  }
 35→}
 36→
 37→/**
 38→ * Get the 8 corner points of a part's bounding box in domain coordinates.
 39→ * @param {Object} part
 40→ * @returns {Array<{x: number, y: number, z: number}>}
 41→ */
 42→export function getPartCorners(part) {
 43→  if (part.type === 'solid') {
 44→    const { base, top } = getSolidVertices(part);
 45→    return [...base, ...top];
 46→  }
 47→
 48→  const { position } = part;
 49→  const dims = getPartDimensions(part);
 50→  const x0 = position.x;
 51→  const y0 = position.y;
 52→  const z0 = position.z;
 53→  const x1 = x0 + dims.width;
 54→  const y1 = y0 + dims.depth;
 55→  const z1 = z0 + dims.height;
 56→
 57→  return [
 58→    { x: x0, y: y0, z: z0 },
 59→    { x: x1, y: y0, z: z0 },
 60→    { x: x0, y: y1, z: z0 },
 61→    { x: x1, y: y1, z: z0 },
 62→    { x: x0, y: y0, z: z1 },
 63→    { x: x1, y: y0, z: z1 },
 64→    { x: x0, y: y1, z: z1 },
 65→    { x: x1, y: y1, z: z1 },
 66→  ];
 67→}
 68→
 69→/**
 70→ * Get the 12 edge midpoints of a part's bounding box.
 71→ * @param {Object} part
 72→ * @returns {Array<{x: number, y: number, z: number}>}
 73→ */
 74→export function getPartEdgeMidpoints(part) {
 75→  if (part.type === 'solid') {
 76→    return getSolidEdgeMidpoints(part);
 77→  }
 78→
 79→  const { position } = part;
 80→  const dims = getPartDimensions(part);
 81→  const x0 = position.x;
 82→  const y0 = position.y;
 83→  const z0 = position.z;
 84→  const x1 = x0 + dims.width;
 85→  const y1 = y0 + dims.depth;
 86→  const z1 = z0 + dims.height;
 87→  const mx = (x0 + x1) / 2;
 88→  const my = (y0 + y1) / 2;
 89→  const mz = (z0 + z1) / 2;
 90→
 91→  return [
 92→    // Bottom face edges (z=z0)
 93→    { x: mx, y: y0, z: z0 },
 94→    { x: mx, y: y1, z: z0 },
 95→    { x: x0, y: my, z: z0 },
 96→    { x: x1, y: my, z: z0 },
 97→    // Top face edges (z=z1)
 98→    { x: mx, y: y0, z: z1 },
 99→    { x: mx, y: y1, z: z1 },
100→    { x: x0, y: my, z: z1 },
101→    { x: x1, y: my, z: z1 },
102→    // Vertical edges
103→    { x: x0, y: y0, z: mz },
104→    { x: x1, y: y0, z: mz },
105→    { x: x0, y: y1, z: mz },
106→    { x: x1, y: y1, z: mz },
107→  ];
