110→/**
111→ * Get the 6 face centers of a part's bounding box.
112→ * @param {Object} part
113→ * @returns {Array<{x: number, y: number, z: number, faceId: string}>}
114→ */
115→export function getPartFaceCenters(part) {
116→  if (part.type === 'solid') {
117→    return getSolidFaceCenters(part);
118→  }
119→
120→  const { position } = part;
121→  const dims = getPartDimensions(part);
122→  const cx = position.x + dims.width / 2;
123→  const cy = position.y + dims.depth / 2;
124→  const cz = position.z + dims.height / 2;
125→
126→  return [
127→    { x: cx, y: cy, z: position.z + dims.height, faceId: '+z' },
128→    { x: cx, y: cy, z: position.z, faceId: '-z' },
129→    { x: position.x + dims.width, y: cy, z: cz, faceId: '+x' },
130→    { x: position.x, y: cy, z: cz, faceId: '-x' },
131→    { x: cx, y: position.y + dims.depth, z: cz, faceId: '+y' },
132→    { x: cx, y: position.y, z: cz, faceId: '-y' },
133→  ];
134→}
