136→/**
137→ * Get the 4 corner points of a specific face.
138→ * @param {Object} part
139→ * @param {string} faceId - '+x', '-x', '+y', '-y', '+z', '-z'
140→ * @returns {Array<{x: number, y: number, z: number}>}
141→ */
142→export function getPartFaceCorners(part, faceId) {
143→  if (part.type === 'solid') {
144→    const { base, top } = getSolidVertices(part);
145→    const bounds = getSolidBounds(part);
146→
147→    const normal = part.plane?.normal || { x: 0, y: 0, z: 1 };
148→    const normalFace = Math.abs(normal.x) > 0.9
149→      ? (normal.x >= 0 ? '+x' : '-x')
150→      : Math.abs(normal.y) > 0.9
151→        ? (normal.y >= 0 ? '+y' : '-y')
152→        : (normal.z >= 0 ? '+z' : '-z');
153→    const oppositeFace = normalFace.startsWith('+')
154→      ? `-${normalFace.slice(1)}`
155→      : `+${normalFace.slice(1)}`;
156→
157→    if (faceId === oppositeFace) return base;
158→    if (faceId === normalFace) return top;
159→
160→    const x0 = bounds.min.x;
161→    const y0 = bounds.min.y;
162→    const z0 = bounds.min.z;
163→    const x1 = bounds.max.x;
164→    const y1 = bounds.max.y;
165→    const z1 = bounds.max.z;
166→
167→    switch (faceId) {
168→      case '+z': return [{ x: x0, y: y0, z: z1 }, { x: x1, y: y0, z: z1 }, { x: x1, y: y1, z: z1 }, { x: x0, y: y1, z: z1 }];
169→      case '-z': return [{ x: x0, y: y0, z: z0 }, { x: x1, y: y0, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x0, y: y1, z: z0 }];
170→      case '+x': return [{ x: x1, y: y0, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x1, y: y1, z: z1 }, { x: x1, y: y0, z: z1 }];
171→      case '-x': return [{ x: x0, y: y0, z: z0 }, { x: x0, y: y1, z: z0 }, { x: x0, y: y1, z: z1 }, { x: x0, y: y0, z: z1 }];
172→      case '+y': return [{ x: x0, y: y1, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x1, y: y1, z: z1 }, { x: x0, y: y1, z: z1 }];
173→      case '-y': return [{ x: x0, y: y0, z: z0 }, { x: x1, y: y0, z: z0 }, { x: x1, y: y0, z: z1 }, { x: x0, y: y0, z: z1 }];
174→      default: return [];
175→    }
176→  }
177→
178→  const { position } = part;
179→  const dims = getPartDimensions(part);
180→  const x0 = position.x;
181→  const y0 = position.y;
182→  const z0 = position.z;
183→  const x1 = x0 + dims.width;
184→  const y1 = y0 + dims.depth;
185→  const z1 = z0 + dims.height;
186→
187→  switch (faceId) {
188→    case '+z': return [{ x: x0, y: y0, z: z1 }, { x: x1, y: y0, z: z1 }, { x: x1, y: y1, z: z1 }, { x: x0, y: y1, z: z1 }];
189→    case '-z': return [{ x: x0, y: y0, z: z0 }, { x: x1, y: y0, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x0, y: y1, z: z0 }];
190→    case '+x': return [{ x: x1, y: y0, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x1, y: y1, z: z1 }, { x: x1, y: y0, z: z1 }];
191→    case '-x': return [{ x: x0, y: y0, z: z0 }, { x: x0, y: y1, z: z0 }, { x: x0, y: y1, z: z1 }, { x: x0, y: y0, z: z1 }];
192→    case '+y': return [{ x: x0, y: y1, z: z0 }, { x: x1, y: y1, z: z0 }, { x: x1, y: y1, z: z1 }, { x: x0, y: y1, z: z1 }];
193→    case '-y': return [{ x: x0, y: y0, z: z0 }, { x: x1, y: y0, z: z0 }, { x: x1, y: y0, z: z1 }, { x: x0, y: y0, z: z1 }];
194→    default: return [];
195→  }
196→}
