215→/**
216→ * Convert plane-local (u, v) to Three.js world coordinates.
217→ * Domain: x=x, y=y, z=z -> Three.js: x=x, y=z, z=y
218→ */
219→function planeToThree(plane, u, v) {
220→  const wx = plane.origin.x + u * plane.uAxis.x + v * plane.vAxis.x;
221→  const wy = plane.origin.y + u * plane.uAxis.y + v * plane.vAxis.y;
222→  const wz = plane.origin.z + u * plane.uAxis.z + v * plane.vAxis.z;
223→  // Convert domain coords to Three.js coords
224→  return { x: wx, y: wz, z: wy };
225→}
226→
227→function domainVectorToThree(vector) {
228→  return new THREE.Vector3(vector.x, vector.z, vector.y);
229→}
230→
231→function makePlaneBasisMatrix(plane) {
232→  const uAxis = domainVectorToThree(plane.uAxis);
233→  const vAxis = domainVectorToThree(plane.vAxis);
234→  const normal = domainVectorToThree(plane.normal);
235→  const origin = new THREE.Vector3(plane.origin.x, plane.origin.z, plane.origin.y);
236→  const matrix = new THREE.Matrix4().makeBasis(uAxis, vAxis, normal);
237→  matrix.setPosition(origin);
238→  return matrix;
239→}
