 1→/**
 2→ * Extrusion computation - pure functions for push/pull.
 3→ * Creates new part specs from face + distance.
 4→ */
 5→
 6→import { generateId } from '@/domain/ids';
 7→import { getPartDimensions } from './partGeometry';
 8→
 9→/**
10→ * Compute a new part extruded from a face of an existing part.
11→ *
12→ * @param {Object} part - The source part
13→ * @param {string} faceId - Face ID ('+x', '-x', '+y', '-y', '+z', '-z')
14→ * @param {number} distance - Extrusion distance in mm (positive = outward)
15→ * @returns {{ partOverrides: Object, constraint: Object }} New part overrides + constraint config
16→ */
17→export function computeExtrusionFromFace(part, faceId, distance) {
18→  const dims = getPartDimensions(part);
19→  const absDist = Math.abs(distance);
20→  if (absDist < 1) return null;
21→
22→  const pos = { ...part.position };
23→  let newWidth, newDepth, newThickness;
24→
25→  switch (faceId) {
26→    case '+z': // top face - extrude upward
27→      newWidth = dims.width;
28→      newDepth = dims.depth;
29→      newThickness = absDist;
30→      pos.z = part.position.z + dims.height;
31→      break;
32→    case '-z': // bottom face - extrude downward
33→      newWidth = dims.width;
34→      newDepth = dims.depth;
35→      newThickness = absDist;
36→      pos.z = part.position.z - absDist;
37→      break;
38→    case '+x': // right face - extrude right
39→      newWidth = absDist;
40→      newDepth = dims.depth;
41→      newThickness = dims.height;
42→      pos.x = part.position.x + dims.width;
43→      break;
44→    case '-x': // left face - extrude left
45→      newWidth = absDist;
46→      newDepth = dims.depth;
47→      newThickness = dims.height;
48→      pos.x = part.position.x - absDist;
49→      break;
50→    case '+y': // back face - extrude back
51→      newWidth = dims.width;
52→      newDepth = absDist;
53→      newThickness = dims.height;
54→      pos.y = part.position.y + dims.depth;
55→      break;
56→    case '-y': // front face - extrude front
57→      newWidth = dims.width;
58→      newDepth = absDist;
59→      newThickness = dims.height;
60→      pos.y = part.position.y - absDist;
61→      break;
62→    default:
63→      return null;
64→  }
65→
66→  // Determine anchor mapping for constraint
67→  const anchorMap = {
68→    '+z': { sourceAnchor: 'bottom', targetAnchor: 'top' },
69→    '-z': { sourceAnchor: 'top', targetAnchor: 'bottom' },
70→    '+x': { sourceAnchor: 'left', targetAnchor: 'right' },
71→    '-x': { sourceAnchor: 'right', targetAnchor: 'left' },
72→    '+y': { sourceAnchor: 'front', targetAnchor: 'back' },
73→    '-y': { sourceAnchor: 'back', targetAnchor: 'front' },
74→  };
75→
76→  const anchors = anchorMap[faceId];
77→
78→  return {
79→    partOverrides: {
80→      name: 'Panel',
81→      position: pos,
82→      width: newWidth,
83→      depth: newDepth,
84→      thickness: newThickness,
85→      assemblyId: part.assemblyId || null,
86→      objectId: part.objectId || null,
87→    },
88→    constraint: {
89→      type: 'attach_face',
90→      targetPartId: part.id,
91→      sourceAnchor: anchors.sourceAnchor,
92→      targetAnchor: anchors.targetAnchor,
93→      offset: 0,
94→    },
95→  };
96→}
