 131→        const filtered = (constraint.partIds || []).filter((id) => !idsToRemove.has(id));
 132→        // Also clear referencePartId if it was removed
 133→        const refCleared = idsToRemove.has(constraint.referencePartId)
 134→          ? null
 135→          : constraint.referencePartId;
 136→        if (filtered.length < 2) return null; // not enough parts left
 137→        return { ...constraint, partIds: filtered, referencePartId: refCleared };
 138→      }
 139→      // Standard constraints: remove if either source or target is deleted
 140→      if (idsToRemove.has(constraint.sourcePartId) || idsToRemove.has(constraint.targetPartId)) {
 141→        return null;
 142→      }
 143→      return constraint;
 144→    })
 145→    .filter(Boolean);
 146→}
 147→
 148→function removePartsAndAssemblies(project, { partIds, assemblyIds }) {
 149→  const idsToRemove = new Set(partIds);
 150→  const assemblyIdSet = new Set(assemblyIds);
 151→
 152→  const childIds = new Set(
 153→    project.parts.filter((part) => idsToRemove.has(part.parentId)).map((part) => part.id)
 154→  );
 155→  for (const childId of childIds) idsToRemove.add(childId);
 156→
 157→  const constraints = filterConstraintsForRemovedParts(
 158→    project.constraints || [],
 159→    idsToRemove
 160→  );
 161→
 162→  return {
 163→    ...project,
 164→    parts: project.parts
 165→      .filter((part) => !idsToRemove.has(part.id))
 166→      .map((part) => {
 167→        if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 168→          return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 169→        }
 170→        return part;
 171→      }),
 172→    assemblies: project.assemblies.filter((assembly) => !assemblyIdSet.has(assembly.id)),
 173→    constraints,
 174→  };
 175→}
 176→
 177→function removeObjectArtifacts(project, objectId) {
 178→  const partIds = project.parts
 179→    .filter((part) => part.objectId === objectId)
 180→    .map((part) => part.id);
 181→  const assemblyIds = project.assemblies
 182→    .filter((assembly) => assembly.objectId === objectId)
 183→    .map((assembly) => assembly.id);
 184→
 185→  return removePartsAndAssemblies(project, { partIds, assemblyIds });
 186→}
 187→
 188→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
 189→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
 190→
 191→  return (sheets || []).map((sheet) => ({
 192→    ...sheet,
 193→    viewports: (sheet.viewports || []).map((viewport) => {
 194→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
 195→        return viewport;
 196→      }
 197→
 198→      if (viewport.sourceView === 'sketch_assembly_top') {
 199→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
 200→      }
 201→      if (viewport.sourceView === 'sketch_assembly_front') {
 202→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
 203→      }
 204→      if (viewport.sourceView === 'sketch_assembly_side') {
 205→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
 206→      }
 207→      if (viewport.sourceView === 'sketch_part_list') {
 208→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
 209→      }
 210→
 211→      return viewport;
 212→    }),
 213→  }));
 214→}
 215→
 216→function detachManagedObject(project, objectId) {
 217→  return {
 218→    ...project,
 219→    objects: (project.objects || []).map((object) => (
 220→      object.id === objectId
 221→        ? {
 222→            ...object,
 223→            source: 'custom',
 224→            editingPolicy: 'manual',
 225→            templateType: null,
 226→            templateParams: null,
 227→            summary: object.summary || 'Detached custom object',
 228→            updatedAt: new Date().toISOString(),
 229→          }
 230→        : object
 231→    )),
 232→    assemblies: project.assemblies.map((assembly) => (
 233→      assembly.objectId === objectId
 234→        ? {
 235→            ...assembly,
 236→            source: 'manual',
 237→            role: assembly.role || null,
 238→          }
 239→        : assembly
 240→    )),
 241→    parts: project.parts.map((part) => (
 242→      part.objectId === objectId
 243→        ? {
 244→          ...part,
 245→            source: 'manual',
 246→            locked: false,
 247→          }
 248→        : part
 249→    )),
 250→  };
 251→}
 252→
 253→function addGeneratedObject(project, generated) {
 254→  return {
 255→    ...project,
 256→    objects: [...(project.objects || []), generated.object],
 257→    assemblies: [...project.assemblies, ...generated.assemblies],
 258→    parts: [...project.parts, ...generated.parts.map(sanitizePart)],
 259→  };
 260→}
 261→
 262→function collectConstraintsForObject(project, objectId) {
 263→  const objectPartIds = new Set(
 264→    project.parts.filter((part) => part.objectId === objectId).map((part) => part.id)
 265→  );
 266→  return (project.constraints || []).filter((constraint) => {
 267→    if (constraint.type === 'equal_spacing') {
 268→      return (constraint.partIds || []).some((id) => objectPartIds.has(id));
 269→    }
 270→    return objectPartIds.has(constraint.sourcePartId) || objectPartIds.has(constraint.targetPartId);
 271→  });
 272→}
 273→
 274→function buildRoleMap(parts, objectId) {
 275→  const map = new Map();
 276→  for (const part of parts) {
 277→    if (part.objectId === objectId && part.generatedRole) {
 278→      map.set(part.id, part.generatedRole);
 279→    }
 280→  }
 281→  return map;
 282→}
 283→
 284→function buildReverseRoleMap(parts, objectId) {
 285→  const map = new Map();
 286→  for (const part of parts) {
 287→    if (part.objectId === objectId && part.generatedRole) {
 288→      map.set(part.generatedRole, part.id);
 289→    }
 290→  }
 291→  return map;
 292→}
 293→
 294→function remapConstraints(constraints, oldRoleMap, newRoleMap) {
 295→  return constraints
 296→    .map((constraint) => {
 297→      if (constraint.type === 'equal_spacing') {
 298→        const newPartIds = (constraint.partIds || []).map((id) => {
 299→          const role = oldRoleMap.get(id);
 300→          return role ? (newRoleMap.get(role) || null) : id;
 301→        }).filter(Boolean);
 302→
 303→        let newRefId = constraint.referencePartId;
 304→        if (newRefId) {
 305→          const refRole = oldRoleMap.get(newRefId);
 306→          newRefId = refRole ? (newRoleMap.get(refRole) || null) : newRefId;
 307→        }
 308→
 309→        if (newPartIds.length < 2) return null;
 310→        return { ...constraint, partIds: newPartIds, referencePartId: newRefId };
 311→      }
 312→
 313→      let newSourceId = constraint.sourcePartId;
 314→      let newTargetId = constraint.targetPartId;
 315→
 316→      const sourceRole = oldRoleMap.get(newSourceId);
 317→      if (sourceRole) newSourceId = newRoleMap.get(sourceRole) || null;
 318→
 319→      const targetRole = oldRoleMap.get(newTargetId);
 320→      if (targetRole) newTargetId = newRoleMap.get(targetRole) || null;
 321→
 322→      if (!newSourceId || !newTargetId) return null;
 323→      return { ...constraint, sourcePartId: newSourceId, targetPartId: newTargetId };
 324→    })
 325→    .filter(Boolean);
 326→}
 327→
 328→function rebuildManagedObject(project, object, params) {
 329→  const oldAssemblyIds = project.assemblies
 330→    .filter((assembly) => assembly.objectId === object.id)
 331→    .map((assembly) => assembly.id);
 332→
 333→  // Collect constraints referencing old parts and build role map before stripping
 334→  const affectedConstraints = collectConstraintsForObject(project, object.id);
 335→  const oldRoleMap = buildRoleMap(project.parts, object.id);
 336→
 337→  const strippedProject = removeObjectArtifacts(project, object.id);
 338→  const generated = generateObjectFromTemplate(object.templateType, params, {
 339→    objectId: object.id,
 340→    name: object.name,
 341→    origin: object.origin,
 342→  });
 343→
 344→  const nextProject = addGeneratedObject({
 345→    ...strippedProject,
 346→    objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
 347→    sheets: retargetManagedViewports(strippedProject.sheets, object.id, oldAssemblyIds),
 348→  }, generated);
 349→
 350→  // Remap constraints to new part IDs via role matching
 351→  if (affectedConstraints.length > 0) {
 352→    const newRoleMap = buildReverseRoleMap(nextProject.parts, object.id);
 353→    const remapped = remapConstraints(affectedConstraints, oldRoleMap, newRoleMap);
 354→    // Merge: keep constraints not affected + add remapped ones
 355→    const affectedIds = new Set(affectedConstraints.map((c) => c.id));
 356→    const kept = (nextProject.constraints || []).filter((c) => !affectedIds.has(c.id));
 357→    return { ...nextProject, constraints: [...kept, ...remapped] };
 358→  }
 359→
 360→  return nextProject;
 361→}
 362→
 363→function sketchReducer(state, action) {
 364→  switch (action.type) {
 365→    case 'SKETCH_NEW': {
 366→      const newProject = syncManualObjectDimensions(
 367→        normalizeSketchObjects(action.project || createSketchProject())
 368→      );
 369→      return {
 370→        project: newProject,
 371→        isDirty: false,
 372→        savedSnapshot: snapshotSketch(newProject),
 373→        history: [],
 374→        future: [],
 375→      };
 376→    }
 377→
 378→    case 'SKETCH_LOAD': {
 379→      const loaded = syncManualObjectDimensions(normalizeSketchObjects(action.project));
 380→      return {
 381→        project: loaded,
 382→        isDirty: false,
 383→        savedSnapshot: snapshotSketch(loaded),
 384→        history: [],
 385→        future: [],
 386→      };
 387→    }
 388→
 389→    case 'PART_ADD': {
 390→      const part = sanitizePart(action.part);
 391→      const assembly = part.assemblyId
 392→        ? state.project.assemblies.find((entry) => entry.id === part.assemblyId)
 393→        : null;
 394→      const nextPart = assembly && assembly.objectId
 395→        ? { ...part, objectId: assembly.objectId }
 396→        : part;
 397→      let nextProject = {
 398→        ...state.project,
 399→        updatedAt: new Date().toISOString(),
 400→        parts: [...state.project.parts, nextPart],
 401→      };
 402→      nextProject = applyConstraints(nextProject);
 403→      return applyUpdate(state, nextProject);
 404→    }
 405→
 406→    case 'PART_UPDATE': {
 407→      const managedObject = getManagedObjectForPart(state.project, action.part.id);
 408→      if (managedObject && !action.allowManagedUpdate) return state;
 409→
 410→      let nextProject = {
 411→        ...state.project,
 412→        updatedAt: new Date().toISOString(),
 413→        parts: state.project.parts.map((part) => {
 414→          if (part.id !== action.part.id) return part;
 415→          const merged = mergePart(part, action.part);
 416→          return merged.type === 'dimension' ? merged : sanitizePart(merged);
 417→        }),
 418→      };
 419→      nextProject = applyConstraints(nextProject);
 420→      nextProject = updateBoundDimensions(nextProject, action.part.id);
 421→      return applyUpdate(state, nextProject);
 422→    }
 423→
 424→    case 'PART_DELETE': {
 425→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 426→      if (managedObject) return state;
 427→
 428→      const partId = action.partId;
 429→      const childIds = new Set(
 430→        state.project.parts.filter((part) => part.parentId === partId).map((part) => part.id)
 431→      );
 432→      const idsToRemove = new Set([partId, ...childIds]);
 433→
 434→      const constraints = filterConstraintsForRemovedParts(
 435→        state.project.constraints || [],
 436→        idsToRemove
 437→      );
 438→
 439→      return applyUpdate(state, {
 440→        ...state.project,
 441→        updatedAt: new Date().toISOString(),
 442→        parts: state.project.parts
 443→          .filter((part) => !idsToRemove.has(part.id))
 444→          .map((part) => {
 445→            if (part.type === 'dimension' && part.boundPartId && idsToRemove.has(part.boundPartId)) {
 446→              return { ...part, boundPartId: null, boundProperty: null, boundAxis: null };
 447→            }
 448→            return part;
 449→          }),
 450→        assemblies: state.project.assemblies.map((assembly) => ({
 451→          ...assembly,
 452→          partIds: assembly.partIds.filter((id) => !idsToRemove.has(id)),
 453→        })),
 454→        constraints,
 455→      });
 456→    }
 457→
 458→    case 'PART_CLONE': {
 459→      const managedObject = getManagedObjectForPart(state.project, action.partId);
 460→      if (managedObject) return state;
 461→
 462→      const part = state.project.parts.find((entry) => entry.id === action.partId);
 463→      if (!part) return state;
 464→
 465→      const idMap = new Map();
 466→      const cloned = clonePart(part, idMap);
 467→      const children = state.project.parts.filter((entry) => entry.parentId === action.partId);
 468→      const clonedChildren = children.map((child) => {
 469→        const clonedChild = clonePart(child, idMap);
 470→        clonedChild.parentId = cloned.id;
 471→        return clonedChild;
 472→      });
 473→
 474→      const newParts = [cloned, ...clonedChildren];
 475→      let assemblies = state.project.assemblies;
 476→      if (part.assemblyId) {
 477→        assemblies = assemblies.map((assembly) => {
 478→          if (assembly.id === part.assemblyId) {
 479→            return {
 480→              ...assembly,
 481→              partIds: [...assembly.partIds, ...newParts.map((entry) => entry.id)],
 482→            };
 483→          }
 484→          return assembly;
 485→        });
 486→        for (const nextPart of newParts) {
 487→          nextPart.assemblyId = part.assemblyId;
 488→        }
 489→      }
 490→
 491→      return applyUpdate(state, {
 492→        ...state.project,
 493→        updatedAt: new Date().toISOString(),
 494→        parts: [...state.project.parts, ...newParts],
 495→        assemblies,
 496→      });
 497→    }
 498→
 499→    case 'ASSEMBLY_ADD':
 500→      return applyUpdate(state, {
 501→        ...state.project,
 502→        updatedAt: new Date().toISOString(),
 503→        assemblies: [...state.project.assemblies, { ...action.assembly, source: action.assembly.source || 'manual' }],
 504→      });
 505→
 506→    case 'ASSEMBLY_UPDATE': {
 507→      const managedObject = getManagedObjectForAssembly(state.project, action.assembly.id);
 508→      if (managedObject) return state;
 509→
 510→      return applyUpdate(state, {
 511→        ...state.project,
 512→        updatedAt: new Date().toISOString(),
 513→        assemblies: state.project.assemblies.map((assembly) => (
 514→          assembly.id === action.assembly.id ? { ...assembly, ...action.assembly } : assembly
 515→        )),
 516→      });
 517→    }
 518→
 519→    case 'ASSEMBLY_DELETE': {
 520→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 521→      if (managedObject) return state;
 522→
 523→      const assemblyId = action.assemblyId;
 524→      return applyUpdate(state, {
 525→        ...state.project,
 526→        updatedAt: new Date().toISOString(),
 527→        assemblies: state.project.assemblies.filter((assembly) => assembly.id !== assemblyId),
 528→        parts: state.project.parts.map((part) => (
 529→          part.assemblyId === assemblyId ? { ...part, assemblyId: null } : part
 530→        )),
 531→      });
 532→    }
 533→
 534→    case 'ASSEMBLY_MOVE': {
 535→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 536→      if (managedObject) {
 537→        return sketchReducer(state, {
 538→          type: 'OBJECT_MOVE',
 539→          objectId: managedObject.id,
 540→          delta: action.delta,
 541→        });
 542→      }
 543→
 544→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 545→      if (!assembly) return state;
 546→
 547→      const partIdSet = new Set(assembly.partIds);
 548→      let nextProject = {
 549→        ...state.project,
 550→        updatedAt: new Date().toISOString(),
 551→        parts: state.project.parts.map((part) => {
 552→          if (!partIdSet.has(part.id) || part.type === 'dimension') return part;
 553→          const moved = {
 554→            ...part,
 555→            position: {
 556→              x: part.position.x + (action.delta.dx || 0),
 557→              y: part.position.y + (action.delta.dy || 0),
 558→              z: part.position.z + (action.delta.dz || 0),
 559→            },
 560→          };
 561→          return sanitizePart(moved);
 562→        }),
 563→      };
 564→      nextProject = applyConstraints(nextProject);
 565→      for (const partId of partIdSet) {
 566→        nextProject = updateBoundDimensions(nextProject, partId);
 567→      }
 568→      return applyUpdate(state, nextProject);
 569→    }
 570→
 571→    case 'ASSEMBLY_DELETE_WITH_PARTS': {
 572→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 573→      if (managedObject) {
 574→        return sketchReducer(state, {
 575→          type: 'OBJECT_DELETE',
 576→          objectId: managedObject.id,
 577→        });
 578→      }
 579→
 580→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 581→      if (!assembly) return state;
 582→
 583→      return applyUpdate(state, {
 584→        ...removePartsAndAssemblies(state.project, {
 585→          partIds: assembly.partIds,
 586→          assemblyIds: [assembly.id],
 587→        }),
 588→        updatedAt: new Date().toISOString(),
 589→      });
 590→    }
 591→
 592→    case 'ASSEMBLY_ADD_PART': {
 593→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 594→      if (managedObject) return state;
 595→
 596→       const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 597→
 598→      return applyUpdate(state, {
 599→        ...state.project,
 600→        updatedAt: new Date().toISOString(),
 601→        assemblies: state.project.assemblies.map((assembly) => (
 602→          assembly.id === action.assemblyId && !assembly.partIds.includes(action.partId)
 603→            ? { ...assembly, partIds: [...assembly.partIds, action.partId] }
 604→            : assembly
 605→        )),
 606→        parts: state.project.parts.map((part) => (
 607→          part.id === action.partId
 608→            ? { ...part, assemblyId: action.assemblyId, objectId: assembly?.objectId || part.objectId || null }
 609→            : part
 610→        )),
 611→      });
 612→    }
 613→
 614→    case 'ASSEMBLY_REMOVE_PART': {
 615→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 616→      if (managedObject) return state;
 617→
 618→      return applyUpdate(state, {
 619→        ...state.project,
 620→        updatedAt: new Date().toISOString(),
 621→        assemblies: state.project.assemblies.map((assembly) => (
 622→          assembly.id === action.assemblyId
 623→            ? { ...assembly, partIds: assembly.partIds.filter((id) => id !== action.partId) }
 624→            : assembly
 625→        )),
 626→        parts: state.project.parts.map((part) => (
 627→          part.id === action.partId && part.assemblyId === action.assemblyId
 628→            ? { ...part, assemblyId: null }
 629→            : part
 630→        )),
 631→      });
 632→    }
 633→
 634→    case 'ASSEMBLY_CLONE': {
 635→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 636→      if (managedObject) return state;
 637→
 638→      const assembly = state.project.assemblies.find((entry) => entry.id === action.assemblyId);
 639→      if (!assembly) return state;
 640→
 641→      const idMap = new Map();
 642→      const newAssemblyId = generateId('asm');
 643→      const newAssembly = {
 644→        ...assembly,
 645→        id: newAssemblyId,
 646→        name: `${assembly.name} (copy)`,
 647→        partIds: [],
 648→        objectId: assembly.objectId || null,
 649→        source: 'manual',
 650→      };
 651→
 652→      const assemblyParts = state.project.parts.filter((part) => part.assemblyId === action.assemblyId);
 653→      const clonedParts = [];
 654→
 655→      for (const part of assemblyParts) {
 656→        const cloned = clonePart(part, idMap);
 657→        cloned.assemblyId = newAssemblyId;
 658→        clonedParts.push(cloned);
 659→      }
 660→
 661→      for (const clonedPart of clonedParts) {
 662→        if (clonedPart.parentId && idMap.has(clonedPart.parentId)) {
 663→          clonedPart.parentId = idMap.get(clonedPart.parentId);
 664→        }
 665→      }
 666→
 667→      newAssembly.partIds = clonedParts.map((part) => part.id);
 668→
 669→      return applyUpdate(state, {
 670→        ...state.project,
 671→        updatedAt: new Date().toISOString(),
 672→        parts: [...state.project.parts, ...clonedParts],
 673→        assemblies: [...state.project.assemblies, newAssembly],
 674→      });
 675→    }
 676→
 677→    case 'OBJECT_ADD':
 678→      return applyUpdate(state, {
 679→        ...state.project,
 680→        updatedAt: new Date().toISOString(),
 681→        objects: [...(state.project.objects || []), createSketchObject(action.object.name, action.object)],
 682→      });
 683→
 684→    case 'OBJECT_CREATE': {
 685→      const object = createSketchObject(action.object.name, action.object);
 686→      const assemblies = (action.assemblies || []).map((assembly) => createAssembly(assembly.name, assembly));
 687→      return applyUpdate(state, {
 688→        ...state.project,
 689→        updatedAt: new Date().toISOString(),
 690→        objects: [...(state.project.objects || []), object],
 691→        assemblies: [...state.project.assemblies, ...assemblies],
 692→      });
 693→    }
 694→
 695→    case 'OBJECT_UPDATE':
 696→      return applyUpdate(state, {
 697→        ...state.project,
 698→        updatedAt: new Date().toISOString(),
 699→        objects: (state.project.objects || []).map((object) => (
 700→          object.id === action.object.id
 701→            ? {
 702→                ...object,
 703→                ...action.object,
 704→                templateParams: action.object.templateParams
 705→                  ? { ...action.object.templateParams }
 706→                  : object.templateParams,
 707→                dimensions: action.object.dimensions
 708→                  ? { ...action.object.dimensions }
 709→                  : object.dimensions,
 710→                updatedAt: new Date().toISOString(),
 711→              }
 712→            : object
 713→        )),
 714→      });
 715→
 716→    case 'OBJECT_RESIZE': {
 717→      const object = getManagedObject(state.project, action.objectId);
 718→      if (!object || object.editingPolicy === 'parametric') return state;
 719→
 720→      const now = new Date().toISOString();
 721→      const objectParts = state.project.parts.filter((part) => part.objectId === object.id);
 722→      const geometryParts = objectParts.filter(isObjectGeometryPart);
 723→      const requestedDimensions = action.dimensions || {};
 724→
 725→      if (geometryParts.length === 0) {
 726→        const nextDimensions = {
 727→          ...object.dimensions,
 728→          ...(Number.isFinite(requestedDimensions.width) ? { width: clampDimension(requestedDimensions.width) } : {}),
 729→          ...(Number.isFinite(requestedDimensions.depth) ? { depth: clampDimension(requestedDimensions.depth) } : {}),
 730→          ...(Number.isFinite(requestedDimensions.height) ? { height: clampDimension(requestedDimensions.height) } : {}),
 731→        };
 732→
 733→        const unchanged = (
 734→          object.dimensions?.width === nextDimensions.width
 735→          && object.dimensions?.depth === nextDimensions.depth
 736→          && object.dimensions?.height === nextDimensions.height
 737→        );
 738→        if (unchanged) return state;
 739→
 740→        return applyUpdate(state, {
 741→          ...state.project,
 742→          updatedAt: now,
 743→          objects: (state.project.objects || []).map((entry) => (
 744→            entry.id === object.id
 745→              ? {
 746→                  ...entry,
 747→                  dimensions: nextDimensions,
 748→                  updatedAt: now,
 749→                }
 750→              : entry
 751→          )),
 752→        });
 753→      }
 754→
 755→      const currentBounds = getPartsBounds3d(geometryParts);
 756→      const { nextDimensions, scaleFactors } = buildObjectScaleFactors(currentBounds, requestedDimensions);
 757→      const hasScaleChange = hasMeaningfulScaleChange(scaleFactors);
 758→
 759→      if (!hasScaleChange) {
 760→        return state;
 761→      }
 762→
 763→      const anchor = currentBounds.min;
 764→      const resizedPartIds = new Set();
 765→      let nextProject = {
 766→        ...state.project,
 767→        updatedAt: now,
 768→        objects: (state.project.objects || []).map((entry) => (
 769→          entry.id === object.id
 770→            ? {
 771→                ...entry,
 772→                origin: scalePoint3d(entry.origin, anchor, scaleFactors),
 773→                dimensions: nextDimensions,
 774→                updatedAt: now,
 775→              }
 776→            : entry
 777→        )),
 778→        parts: state.project.parts.map((part) => {
 779→          if (part.objectId !== object.id) return part;
 780→          const resized = resizePartForObject(part, anchor, scaleFactors);
 781→          if (part.type !== 'dimension') {
 782→            resizedPartIds.add(part.id);
 783→            return sanitizePart(resized);
 784→          }
 785→          return resized;
 786→        }),
 787→      };
 788→
 789→      nextProject = applyConstraints(nextProject);
 790→      for (const partId of resizedPartIds) {
 791→        nextProject = updateBoundDimensions(nextProject, partId);
 792→      }
 793→
 794→      return applyUpdate(state, nextProject);
 795→    }
 796→
 797→    case 'OBJECT_DELETE': {
 798→      const object = getManagedObject(state.project, action.objectId);
 799→      if (!object) return state;
 800→
 801→      const strippedProject = removeObjectArtifacts(state.project, object.id);
 802→      return applyUpdate(state, {
 803→        ...strippedProject,
 804→        updatedAt: new Date().toISOString(),
 805→        objects: (strippedProject.objects || []).filter((entry) => entry.id !== object.id),
 806→      });
 807→    }
 808→
 809→    case 'OBJECT_MOVE': {
 810→      const object = getManagedObject(state.project, action.objectId);
 811→      if (!object) return state;
 812→
 813→      const partIds = new Set(
 814→        state.project.parts.filter((part) => part.objectId === object.id).map((part) => part.id)
 815→      );
 816→
 817→      let nextProject = {
 818→        ...state.project,
 819→        updatedAt: new Date().toISOString(),
 820→        objects: state.project.objects.map((entry) => (
 821→          entry.id === object.id
 822→            ? {
 823→                ...entry,
 824→                origin: {
 825→                  x: entry.origin.x + (action.delta.dx || 0),
 826→                  y: entry.origin.y + (action.delta.dy || 0),
 827→                  z: entry.origin.z + (action.delta.dz || 0),
 828→                },
 829→                updatedAt: new Date().toISOString(),
 830→              }
 831→            : entry
 832→        )),
 833→        parts: state.project.parts.map((part) => {
 834→          if (!partIds.has(part.id) || part.type === 'dimension') return part;
 835→          return sanitizePart({
 836→            ...part,
 837→            position: {
 838→              x: part.position.x + (action.delta.dx || 0),
 839→              y: part.position.y + (action.delta.dy || 0),
 840→              z: part.position.z + (action.delta.dz || 0),
 841→            },
 842→          });
 843→        }),
 844→      };
 845→      nextProject = applyConstraints(nextProject);
 846→      for (const partId of partIds) {
 847→        nextProject = updateBoundDimensions(nextProject, partId);
 848→      }
 849→      return applyUpdate(state, nextProject);
 850→    }
 851→
 852→    case 'OBJECT_DETACH': {
 853→      const object = getManagedObject(state.project, action.objectId);
 854→      if (!object) return state;
 855→      return applyUpdate(state, {
 856→        ...detachManagedObject(state.project, object.id),
 857→        updatedAt: new Date().toISOString(),
 858→      });
 859→    }
 860→
 861→    case 'CONSTRAINT_ADD': {
 862→      const constraints = [...(state.project.constraints || []), action.constraint];
 863→      let nextProject = {
 864→        ...state.project,
 865→        updatedAt: new Date().toISOString(),
 866→        constraints,
 867→      };
 868→      nextProject = applyConstraints(nextProject);
 869→      return applyUpdate(state, nextProject);
 870→    }
 871→
 872→    case 'CONSTRAINT_UPDATE': {
 873→      const constraints = (state.project.constraints || []).map((constraint) => (
 874→        constraint.id === action.constraint.id ? { ...constraint, ...action.constraint } : constraint
 875→      ));
 876→      let nextProject = {
 877→        ...state.project,
 878→        updatedAt: new Date().toISOString(),
 879→        constraints,
 880→      };
 881→      nextProject = applyConstraints(nextProject);
 882→      return applyUpdate(state, nextProject);
 883→    }
 884→
 885→    case 'CONSTRAINT_DELETE': {
 886→      const constraints = (state.project.constraints || []).filter(
 887→        (constraint) => constraint.id !== action.constraintId
 888→      );
 889→      return applyUpdate(state, {
 890→        ...state.project,
 891→        updatedAt: new Date().toISOString(),
 892→        constraints,
 893→      });
 894→    }
 895→
 896→    case 'ANNOTATION_ADD':
 897→      return applyUpdate(state, {
 898→        ...state.project,
 899→        updatedAt: new Date().toISOString(),
 900→        annotations: [...(state.project.annotations || []), action.annotation],
 901→      });
 902→
 903→    case 'ANNOTATION_UPDATE':
 904→      return applyUpdate(state, {
 905→        ...state.project,
 906→        updatedAt: new Date().toISOString(),
 907→        annotations: (state.project.annotations || []).map((annotation) => (
 908→          annotation.id === action.annotation.id ? { ...annotation, ...action.annotation } : annotation
 909→        )),
 910→      });
 911→
 912→    case 'ANNOTATION_DELETE':
 913→      return applyUpdate(state, {
 914→        ...state.project,
 915→        updatedAt: new Date().toISOString(),
 916→        annotations: (state.project.annotations || []).filter((annotation) => annotation.id !== action.annotationId),
 917→      });
 918→
 919→    case 'PROJECT_UPDATE_META':
 920→      return applyUpdate(state, {
 921→        ...state.project,
 922→        updatedAt: new Date().toISOString(),
 923→        ...action.meta,
 924→      });
 925→
 926→    case 'SKETCH_SHEET_ADD':
 927→      return applyUpdate(state, {
 928→        ...state.project,
 929→        updatedAt: new Date().toISOString(),
 930→        sheets: [...(state.project.sheets || []), action.sheet],
 931→      });
 932→
 933→    case 'SKETCH_SHEET_UPDATE':
 934→      return applyUpdate(state, {
 935→        ...state.project,
 936→        updatedAt: new Date().toISOString(),
 937→        sheets: (state.project.sheets || []).map((sheet) => (
 938→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 939→        )),
 940→      });
 941→
 942→    case 'SKETCH_SHEET_DELETE':
 943→      return applyUpdate(state, {
 944→        ...state.project,
 945→        updatedAt: new Date().toISOString(),
 946→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
 947→      });
 948→
 949→    case 'SKETCH_SHEET_VIEWPORT_ADD': {
 950→      const targetSheet = (state.project.sheets || []).find((sheet) => sheet.id === action.sheetId);
 951→      if (!targetSheet) return state;
 952→      return applyUpdate(state, {
 953→        ...state.project,
 954→        updatedAt: new Date().toISOString(),
 955→        sheets: state.project.sheets.map((sheet) => (
 956→          sheet.id === action.sheetId
 957→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
 958→            : sheet
 959→        )),
 960→      });
 961→    }
 962→
 963→    case 'SKETCH_SHEET_VIEWPORT_UPDATE':
 964→      return applyUpdate(state, {
 965→        ...state.project,
 966→        updatedAt: new Date().toISOString(),
 967→        sheets: (state.project.sheets || []).map((sheet) => (
 968→          sheet.id === action.sheetId
 969→            ? {
 970→                ...sheet,
 971→                viewports: (sheet.viewports || []).map((viewport) => (
 972→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
 973→                )),
 974→              }
 975→            : sheet
 976→        )),
 977→      });
 978→
 979→    case 'SKETCH_SHEET_VIEWPORT_DELETE':
 980→      return applyUpdate(state, {
 981→        ...state.project,
 982→        updatedAt: new Date().toISOString(),
 983→        sheets: (state.project.sheets || []).map((sheet) => (
 984→          sheet.id === action.sheetId
 985→            ? { ...sheet, viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId) }
 986→            : sheet
 987→        )),
 988→      });
 989→
 990→    case 'TEMPLATE_GENERATE': {
 991→      const generated = generateObjectFromTemplate(action.templateType, action.params, {
 992→        objectId: action.objectId,
 993→        name: action.name,
 994→        origin: action.origin,
 995→      });
 996→      return applyUpdate(state, {
 997→        ...addGeneratedObject(state.project, generated),
 998→        updatedAt: new Date().toISOString(),
 999→      });
1000→    }
1001→
1002→    case 'TEMPLATE_REGENERATE': {
1003→      const object = action.objectId
1004→        ? getManagedObject(state.project, action.objectId)
1005→        : getManagedObjectForAssembly(state.project, action.assemblyId);
1006→      if (!object || !object.templateType) return state;
1007→
1008→      const nextProject = rebuildManagedObject(state.project, object, action.params);
1009→      return applyUpdate(state, {
1010→        ...nextProject,
1011→        updatedAt: new Date().toISOString(),
1012→      });
1013→    }
1014→
1015→    case 'TEMPLATE_DETACH': {
1016→      const object = action.objectId
1017→        ? getManagedObject(state.project, action.objectId)
1018→        : getManagedObjectForAssembly(state.project, action.assemblyId);
1019→      if (!object) return state;
1020→      return sketchReducer(state, { type: 'OBJECT_DETACH', objectId: object.id });
1021→    }
1022→
1023→    case 'UNDO': {
1024→      if (state.history.length === 0) return state;
1025→      const previous = state.history[state.history.length - 1];
1026→      return {
1027→        ...state,
1028→        project: previous,
1029→        history: state.history.slice(0, -1),
1030→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
1031→        isDirty: snapshotSketch(previous) !== state.savedSnapshot,
1032→      };
1033→    }
1034→
1035→    case 'REDO': {
1036→      if (state.future.length === 0) return state;
1037→      const next = state.future[0];
1038→      return {
1039→        ...state,
1040→        project: next,
1041→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
1042→        future: state.future.slice(1),
1043→        isDirty: snapshotSketch(next) !== state.savedSnapshot,
1044→      };
1045→    }
1046→
1047→    case 'MARK_SAVED':
1048→      return {
1049→        ...state,
1050→        isDirty: false,
1051→        savedSnapshot: snapshotSketch(state.project),
1052→      };
1053→
1054→    default:
1055→      return state;
1056→  }
1057→}
1058→
1059→function createInitialState(project) {
1060→  return {
1061→    project: syncManualObjectDimensions(normalizeSketchObjects(project)),
1062→    isDirty: false,
1063→    savedSnapshot: snapshotSketch(syncManualObjectDimensions(normalizeSketchObjects(project))),
1064→    history: [],
1065→    future: [],
1066→  };
1067→}
1068→
1069→export function SketchProvider({ children, initialProject }) {
1070→  const [state, dispatch] = useReducer(
1071→    sketchReducer,
1072→    syncManualObjectDimensions(normalizeSketchObjects(initialProject || createSketchProject())),
1073→    createInitialState
1074→  );
1075→
1076→  return (
1077→    <SketchContext.Provider value={{ state, dispatch }}>
1078→      {children}
1079→    </SketchContext.Provider>
1080→  );
1081→}
1082→
1083→export function useSketch() {
1084→  const ctx = useContext(SketchContext);
1085→  if (!ctx) throw new Error('useSketch must be used within SketchProvider');
1086→  const { state, dispatch } = ctx;
1087→
1088→  const getPart = useCallback(
1089→    (partId) => state.project.parts.find((part) => part.id === partId) || null,
1090→    [state.project.parts]
1091→  );
1092→
1093→  const getAssembly = useCallback(
1094→    (assemblyId) => state.project.assemblies.find((assembly) => assembly.id === assemblyId) || null,
1095→    [state.project.assemblies]
1096→  );
1097→
1098→  const getObject = useCallback(
1099→    (objectId) => (state.project.objects || []).find((object) => object.id === objectId) || null,
1100→    [state.project.objects]
1101→  );
1102→
1103→  const getPartsForAssembly = useCallback(
1104→    (assemblyId) => state.project.parts.filter((part) => part.assemblyId === assemblyId),
1105→    [state.project.parts]
1106→  );
1107→
1108→  const getChildParts = useCallback(
1109→    (parentId) => state.project.parts.filter((part) => part.parentId === parentId),
1110→    [state.project.parts]
1111→  );
1112→
1113→  const getAssembliesForObject = useCallback(
1114→    (objectId) => state.project.assemblies.filter((assembly) => assembly.objectId === objectId),
1115→    [state.project.assemblies]
1116→  );
1117→
1118→  return {
1119→    project: state.project,
1120→    isDirty: state.isDirty,
1121→    canUndo: state.history.length > 0,
1122→    canRedo: state.future.length > 0,
1123→    dispatch,
1124→    getPart,
1125→    getAssembly,
1126→    getObject,
1127→    getPartsForAssembly,
1128→    getChildParts,
1129→    getAssembliesForObject,
1130→  };
1131→}
