 1→/**
 2→ * Simple memoization cache for inference points.
 3→ * Recomputes only when the parts array reference changes (React immutability).
 4→ */
 5→
 6→import { collectInferencePoints } from './inferenceEngine';
 7→
 8→/**
 9→ * @returns {{ getPoints: (parts: Array, excludePartId?: string) => InferencePoint[], invalidate: () => void }}
10→ */
11→export function createInferenceCache() {
12→  let cachedParts = null;
13→  let cachedExcludeId = null;
14→  let cachedPoints = null;
15→
16→  return {
17→    /**
18→     * Get inference points, recomputing only if parts ref or excludePartId changed.
19→     */
20→    getPoints(parts, excludePartId = null) {
21→      if (parts === cachedParts && excludePartId === cachedExcludeId && cachedPoints) {
22→        return cachedPoints;
23→      }
24→      cachedParts = parts;
25→      cachedExcludeId = excludePartId;
26→      cachedPoints = collectInferencePoints(parts, { excludePartId });
27→      return cachedPoints;
28→    },
29→
30→    /**
31→     * Force recomputation on next call.
32→     */
33→    invalidate() {
34→      cachedParts = null;
35→      cachedExcludeId = null;
36→      cachedPoints = null;
37→    },
38→  };
39→}
