  4→const FACE_ANCHOR_MAP = {
  5→  '+z': { sourceAnchor: 'bottom', targetAnchor: 'top', planeAxes: [
  6→    { axis: 'x', startAnchor: 'left', endAnchor: 'right' },
  7→    { axis: 'y', startAnchor: 'front', endAnchor: 'back' },
  8→  ] },
  9→  '-z': { sourceAnchor: 'top', targetAnchor: 'bottom', planeAxes: [
 10→    { axis: 'x', startAnchor: 'left', endAnchor: 'right' },
 11→    { axis: 'y', startAnchor: 'front', endAnchor: 'back' },
 12→  ] },
 13→  '+x': { sourceAnchor: 'left', targetAnchor: 'right', planeAxes: [
 14→    { axis: 'y', startAnchor: 'front', endAnchor: 'back' },
 15→    { axis: 'z', startAnchor: 'bottom', endAnchor: 'top' },
 16→  ] },
 17→  '-x': { sourceAnchor: 'right', targetAnchor: 'left', planeAxes: [
 18→    { axis: 'y', startAnchor: 'front', endAnchor: 'back' },
 19→    { axis: 'z', startAnchor: 'bottom', endAnchor: 'top' },
 20→  ] },
 21→  '+y': { sourceAnchor: 'front', targetAnchor: 'back', planeAxes: [
 22→    { axis: 'x', startAnchor: 'left', endAnchor: 'right' },
 23→    { axis: 'z', startAnchor: 'bottom', endAnchor: 'top' },
 24→  ] },
 25→  '-y': { sourceAnchor: 'back', targetAnchor: 'front', planeAxes: [
 26→    { axis: 'x', startAnchor: 'left', endAnchor: 'right' },
 27→    { axis: 'z', startAnchor: 'bottom', endAnchor: 'top' },
 28→  ] },
 29→};
 30→
 31→function getAxisSize(extents, axis) {
 32→  switch (axis) {
 33→    case 'x':
 34→      return extents.width;
 35→    case 'y':
 36→      return extents.depth;
 37→    case 'z':
 38→      return extents.height;
 39→    default:
 40→      return 0;
 41→  }
 42→}
 43→
 44→function normalizePosition(position, axis, sign, size) {
 45→  if (sign < 0) {
 46→    return { ...position, [axis]: position[axis] - size };
 47→  }
 48→  return position;
 49→}
 50→
 51→export function computeFaceAlignedPartOverrides(plane, faceId, worldPos, uSize, vSize, partType) {
 52→  const defaults = PART_DEFAULTS[partType] || {};
 53→  const normal = plane?.normal || { x: 0, y: 0, z: 1 };
 54→  const position = { x: worldPos.x, y: worldPos.y, z: worldPos.z };
 55→  const isHorizontal = Math.abs(normal.z) > 0.5;
 56→  const isXFacing = Math.abs(normal.x) > 0.5;
 57→  const isYFacing = Math.abs(normal.y) > 0.5;
 58→
 59→  if (isHorizontal) {
 60→    if (partType === 'panel') {
 61→      const thickness = defaults.thickness || 18;
 62→      return {
 63→        position: normalizePosition(position, 'z', normal.z, thickness),
 64→        width: uSize,
 65→        depth: vSize,
 66→        thickness,
 67→      };
 68→    }
 69→    if (partType === 'leg') {
 70→      const height = defaults.height || 720;
 71→      return {
 72→        position: normalizePosition(position, 'z', normal.z, height),
 73→        width: uSize,
 74→        depth: vSize,
 75→        height,
 76→      };
 77→    }
 78→    if (partType === 'frame') {
 79→      const height = defaults.height || 60;
 80→      return {
 81→        position: normalizePosition(position, 'z', normal.z, height),
 82→        length: uSize,
 83→        width: vSize,
 84→        height,
 85→        axis: 'x',
 86→      };
 87→    }
 88→    return { position, width: uSize, depth: vSize };
 89→  }
 90→
 91→  if (isXFacing) {
 92→    if (partType === 'panel') {
 93→      const width = defaults.thickness || 18;
 94→      return {
 95→        position: normalizePosition(position, 'x', normal.x, width),
 96→        width,
 97→        depth: uSize,
 98→        thickness: vSize,
 99→      };
100→    }
101→    if (partType === 'leg') {
102→      const width = defaults.width || 40;
103→      return {
104→        position: normalizePosition(position, 'x', normal.x, width),
105→        width,
106→        depth: uSize,
107→        height: vSize,
108→      };
109→    }
110→    if (partType === 'frame') {
111→      const width = defaults.width || 40;
112→      return {
113→        position: normalizePosition(position, 'x', normal.x, width),
114→        width,
115→        height: vSize,
116→        length: uSize,
117→        axis: 'y',
118→      };
119→    }
120→    return { position, width: defaults.width || 40, depth: uSize };
121→  }
122→
123→  if (isYFacing) {
124→    if (partType === 'panel') {
125→      const depth = defaults.thickness || 18;
126→      return {
127→        position: normalizePosition(position, 'y', normal.y, depth),
128→        width: uSize,
129→        depth,
130→        thickness: vSize,
131→      };
132→    }
133→    if (partType === 'leg') {
134→      const depth = defaults.depth || 40;
135→      return {
136→        position: normalizePosition(position, 'y', normal.y, depth),
137→        width: uSize,
138→        depth,
139→        height: vSize,
140→      };
141→    }
142→    if (partType === 'frame') {
143→      const width = defaults.width || 40;
144→      return {
145→        position: normalizePosition(position, 'y', normal.y, width),
146→        length: uSize,
147→        width,
148→        height: vSize,
149→        axis: 'x',
150→      };
151→    }
152→    return { position, width: uSize, depth: defaults.depth || 40 };
153→  }
154→
155→  return { position, width: uSize, depth: vSize };
156→}
